export const Catalog: React.FC = () => {
  const { user } = useAuth();

  // Estados de Vista
  const [selectedArea, setSelectedArea] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  // ESTADO DE SEGREGACIÓN (PESTAÑAS VIGENTE vs HISTORICO)
  const [viewTab, setViewTab] = useState<'active' | 'history'>('active');

  // Estados de Datos
  const [areaProcedures, setAreaProcedures] = useState<Procedure[]>([]);
  const [areaFolders, setAreaFolders] = useState<Folder[]>([]);
  const [loading, setLoading] = useState(false);

  // Estados de Áreas (Fuente de Verdad: Tabla 'departments')
  const [availableAreas, setAvailableAreas] = useState<string[]>([]);

  // Estados de Administración de Áreas
  const [isManageMode, setIsManageMode] = useState(false);
  const [showAddModal, setShowAddModal] = useState(false);
  const [showRenameModal, setShowRenameModal] = useState<string | null>(null); // Contiene el nombre del área a renombrar
  const [showDeleteModal, setShowDeleteModal] = useState<string | null>(null); // Contiene el nombre del área a eliminar
  const [inputName, setInputName] = useState('');
  const [processing, setProcessing] = useState(false);

  // Estado Toast
  const [toast, setToast] = useState<{msg: string, type: 'success'|'error'} | null>(null);

  // Estado para visualizador de archivos
  const [viewFile, setViewFile] = useState<{url: string, name: string} | null>(null);

  const isAdmin = user?.role === 'admin';

  // LÓGICA DE USUARIO MONO-ÁREA
  // Si no es admin y solo tiene 1 área permitida, saltamos la selección manual.
  const isSingleAreaUser = !isAdmin && user?.allowedAreas.length === 1;

  const showToast = (msg: string, type: 'success' | 'error') => {
      setToast({ msg, type });
      setTimeout(() => setToast(null), 4000);
  };

  // 1. Cargar áreas desde la base de datos (departments)
  const refreshAreas = async () => {
      const dbAreas = await appwriteService.getAllAreas();
      setAvailableAreas(dbAreas);
  };

  useEffect(() => {
    refreshAreas();
  }, []);

  // 2. Efecto de Auto-Selección para Usuarios de Área Única
  useEffect(() => {
      if (isSingleAreaUser && !selectedArea && user?.allowedAreas[0]) {
          setSelectedArea(user.allowedAreas[0]);
      }
  }, [isSingleAreaUser, selectedArea, user]);

  // 3. Filtrar áreas para mostrar (comparación insensible usando normalizeString por si acaso, aunque ya todo es uppercase)
  const displayAreas = availableAreas.filter(area => {
      if (isAdmin) return true;
      const normalizedArea = normalizeString(area);
      return user?.allowedAreas.some(allowed => normalizeString(allowed) === normalizedArea);
  });

  // Carga inicial (o al cambiar búsqueda global)
  useEffect(() => {
    if (searchTerm.length > 2 && user) {
        setLoading(true);
        appwriteService.getProcedures(user, searchTerm).then(docs => {
            setAreaProcedures(docs);
            setLoading(false);
        });
    }
  }, [searchTerm, user]);

  // Cargar contenido cuando se selecciona un ÁREA
  useEffect(() => {
      const loadAreaContent = async () => {
          if (user && selectedArea && !searchTerm) {
              setLoading(true);
              try {
                  // Consultamos Folders y Docs filtrados por ESTA área específica
                  // AHORA appwriteService.getProcedures TRAE TODO (VIGENTE Y CADUCO)
                  const [folders, docs] = await Promise.all([
                      appwriteService.getFolders(selectedArea),
                      appwriteService.getProcedures(user, '', selectedArea)
                  ]);
                  setAreaFolders(folders);
                  setAreaProcedures(docs);
              } catch (e) {
                  console.error(e);
              } finally {
                  setLoading(false);
              }
          }
      };
      loadAreaContent();
  }, [selectedArea, user, searchTerm]); // Agregado searchTerm a dependencia para recargar al limpiar búsqueda

  const handleBack = () => {
      setSearchTerm('');
      // Solo limpiamos el área seleccionada si NO es un usuario obligado a una sola área
      if (!isSingleAreaUser) {
          setSelectedArea(null);
          setAreaProcedures([]);
          setAreaFolders([]);
      }
      // Si es SingleAreaUser, al limpiar searchTerm, el useEffect de loadAreaContent se disparará de nuevo 
      // porque selectedArea sigue seteado y searchTerm ahora es falsy.
  };

  // --- HANDLERS DE GESTIÓN (ADMIN) ---

  const handleCreateArea = async () => {
      if (!inputName.trim()) return;
      setProcessing(true);
      const success = await appwriteService.createArea(inputName.trim());
      if (success) {
          await refreshAreas();
          showToast(`Área "${inputName}" creada correctamente`, 'success');
          setShowAddModal(false);
          setInputName('');
      } else {
          showToast("Error al crear área. Posible duplicado.", 'error');
      }
      setProcessing(false);
  };

  const handleRenameArea = async () => {
      if (!showRenameModal || !inputName.trim()) return;
      setProcessing(true);
      const success = await appwriteService.renameArea(showRenameModal, inputName.trim());
      if (success) {
          await refreshAreas();
          showToast(`Área renombrada a "${inputName}"`, 'success');
          setShowRenameModal(null);
          setInputName('');
      } else {
          showToast("Error al renombrar. Verifica permisos.", 'error');
      }
      setProcessing(false);
  };

  const handleDeleteArea = async () => {
      if (!showDeleteModal) return;
      setProcessing(true);
      const success = await appwriteService.deleteArea(showDeleteModal);
      if (success) {
          await refreshAreas();
          showToast(`Área "${showDeleteModal}" eliminada`, 'success');
          setShowDeleteModal(null);
      } else {
          showToast("Error. El área puede tener datos vinculados.", 'error');
      }
      setProcessing(false);
  };

  // Helper para asignar iconos (ahora busca en mayúsculas)
  const getAreaIcon = (areaName: string) => {
      const upperName = areaName.toUpperCase();
      return AREA_ICONS[upperName] || Box;
  };

  const isSearching = searchTerm.length > 0;

  // Determinar si mostramos el botón de "Atrás"
  // Lógica: Mostrar si está buscando OR (si hay área seleccionada Y NO es usuario de área única)
  const showBackButton = isSearching || (selectedArea && !isSingleAreaUser);

  // --- LÓGICA DE FILTRADO Y AGRUPACIÓN POR PESTAÑA ---

  // Filtramos la lista bruta descargada según la pestaña activa
  const displayedProcedures = areaProcedures.filter(proc => {
      // Normalizar status para ser tolerante a fallos
      const status = (proc.status || 'Vigente').toString(); // Convertir a string

      if (viewTab === 'active') {
          // Si está en pestaña activa, mostramos si NO es Caduco ni Obsoleto
          return status !== 'Caduco' && status !== 'Obsoleto';
      } else {
          // Si está en pestaña histórica, mostramos SOLO Caduco u Obsoleto
          return status === 'Caduco' || status === 'Obsoleto';
      }
  });

  const groupedDocs: { folder: Folder | null, docs: Procedure[] }[] = [];

  areaFolders.forEach(folder => {
      const docsInFolder = displayedProcedures.filter(p => p.folder_id === folder.id);
      if (docsInFolder.length > 0) {
          groupedDocs.push({ folder, docs: docsInFolder });
      }
  });

  const folderIds = areaFolders.map(f => f.id);
  const orphanedDocs = displayedProcedures.filter(p => !p.folder_id || !folderIds.includes(p.folder_id));

  if (orphanedDocs.length > 0) {
      groupedDocs.push({ folder: null, docs: orphanedDocs });
  }

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 min-h-[600px] flex flex-col relative">

      {/* Toast Notification */}
      {toast && <Toast message={toast.msg} type={toast.type} onClose={() => setToast(null)} />}

      {/* TOOLBAR & SEARCH */}
      <div className="p-6 border-b border-gray-100 flex flex-col gap-4 bg-gray-50/30">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">

            {/* Título de Navegación */}
            <div className="flex items-center w-full md:w-auto">
                {showBackButton && (
                    <button 
                        onClick={handleBack}
                        className="mr-3 p-2 hover:bg-white rounded-full text-indigo-700 transition-colors shadow-sm border border-transparent hover:border-gray-200"
                        title={isSearching ? "Limpiar búsqueda" : "Volver a Áreas"}
                    >
                        <ArrowLeft size={20} />
                    </button>
                )}

                <div>
                    {isSearching ? (
                        <h2 className="text-xl font-bold text-gray-800">Resultados de Búsqueda</h2>
                    ) : selectedArea ? (
                        <>
                             <p className="text-xs text-gray-400 uppercase font-bold tracking-wider mb-0.5">
                                 Directorio de Procesos
                             </p>
                             <h2 className="text-xl font-bold text-gray-800 flex items-center uppercase">
                                 {selectedArea}
                             </h2>
                        </>
                    ) : (
                        <div className="flex items-center text-gray-800 font-bold text-lg">
                            <Grid size={20} className="mr-2 text-indigo-600" />
                            Catálogo de Procesos
                        </div>
                    )}
                </div>
            </div>

            <div className="flex items-center gap-3 w-full md:w-auto">
                <div className="relative flex-1 md:w-64">
                    <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={20} />
                    <input 
                        type="text" 
                        placeholder="Buscar globalmente..." 
                        className="w-full pl-10 pr-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-100 focus:border-indigo-400 outline-none transition-all shadow-sm"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>

                {/* BOTÓN DE GESTIÓN PARA ADMINS */}
                {isAdmin && !selectedArea && !isSearching && (
                    <button 
                        onClick={() => setIsManageMode(!isManageMode)}
                        className={`p-2.5 rounded-lg border transition-all ${isManageMode ? 'bg-indigo-600 text-white border-indigo-600 shadow-inner ring-2 ring-indigo-200' : 'bg-white text-gray-500 border-gray-200 hover:border-indigo-300 hover:text-indigo-600 shadow-sm'}`}
                        title={isManageMode ? "Salir de Gestión" : "Gestionar Áreas"}
                    >
                        <Settings size={20} className={isManageMode ? 'animate-spin-slow' : ''} />
                    </button>
                )}
            </div>
        </div>

        {/* Banner informativo de modo gestión */}
        {isManageMode && (
            <div className="bg-indigo-50 border border-indigo-100 text-indigo-700 px-4 py-2 rounded-lg text-sm flex items-center animate-in fade-in slide-in-from-top-2">
                <Info size={16} className="mr-2" />
                <span>Modo de Gestión Activo: Puedes crear, renombrar o eliminar departamentos directamente en la Base de Datos.</span>
            </div>
        )}
      </div>

      {/* CONTENT AREA */}
      <div className="flex-1 p-6 bg-gray-50/10 flex flex-col">

        {/* TABS DE SEGREGACIÓN (SOLO VISIBLES SI HAY UN ÁREA SELECCIONADA Y NO BUSCANDO) */}
        {selectedArea && !isSearching && !loading && (
            <div className="flex space-x-1 bg-gray-100/50 p-1 rounded-lg self-start mb-6 border border-gray-200">
                <button
                    onClick={() => setViewTab('active')}
                    className={`px-4 py-2 text-sm font-bold rounded-md transition-all flex items-center ${
                        viewTab === 'active' 
                        ? 'bg-white text-indigo-700 shadow-sm ring-1 ring-black/5' 
                        : 'text-gray-500 hover:text-gray-700 hover:bg-white/50'
                    }`}
                >
                    <CheckCircle size={16} className="mr-2" />
                    VIGENTES
                </button>
                <button
                    onClick={() => setViewTab('history')}
                    className={`px-4 py-2 text-sm font-bold rounded-md transition-all flex items-center ${
                        viewTab === 'history' 
                        ? 'bg-white text-gray-700 shadow-sm ring-1 ring-black/5' 
                        : 'text-gray-400 hover:text-gray-600 hover:bg-white/50'
                    }`}
                >
                    <Clock size={16} className="mr-2" />
                    HISTÓRICO / CADUCOS
                </button>
            </div>
        )}

        {loading ? (
             <div className="p-12 text-center text-gray-400 flex flex-col items-center">
                 <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-600 mb-4"></div>
                 Sincronizando estantería...
             </div>
        ) : isSearching ? (
             /* VISTA DE RESULTADOS DE BÚSQUEDA (SIN TABS) */
            <div className="space-y-2">
                 {areaProcedures.length === 0 ? (
                     <div className="text-center py-10">
                        <p className="text-gray-400">No se encontraron documentos.</p>
                     </div>
                 ) : (
                    areaProcedures.map(proc => (
                        <div 
                            key={proc.$id} 
                            className="flex items-center justify-between p-4 bg-white rounded-lg border border-gray-100 hover:border-indigo-300 hover:shadow-md transition-all group"
                        >
                            <Link to={`/procedure/${proc.$id}`} className="flex items-center space-x-4 flex-1">
                                <div className="p-2 bg-indigo-50 text-indigo-600 rounded-lg group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                                    <FileText size={20} />
                                </div>
                                <div>
                                    <h4 className="font-bold text-gray-800">{proc.name}</h4>
                                    <p className="text-xs text-gray-500 uppercase">{proc.code} • {proc.area}</p>
                                </div>
                            </Link>

                            <div className="flex items-center gap-2">
                                {proc.attachmentUrl && proc.attachmentUrl !== '#' && (
                                    <button 
                                        onClick={(e) => { e.preventDefault(); setViewFile({ url: proc.attachmentUrl!, name: proc.name }); }}
                                        className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
                                        title="Previsualizar"
                                    >
                                        <Eye size={20} />
                                    </button>
                                )}
                                <Link to={`/procedure/${proc.$id}`}>
                                     <ChevronRight size={16} className="text-gray-300 group-hover:text-indigo-500" />
                                </Link>
                            </div>
                        </div>
                     ))
                 )}
            </div>
        ) : !selectedArea ? (
            /* VISTA NIVEL 1: ESTANTES (ÁREAS) */
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">

                 {/* Tarjeta de AGREGAR (Solo Admin en Modo Gestión) */}
                 {isManageMode && (
                     <button
                        onClick={() => { setInputName(''); setShowAddModal(true); }}
                        className="flex flex-col items-center justify-center p-8 bg-white rounded-2xl border-2 border-dashed border-indigo-300 hover:bg-indigo-50 transition-all group min-h-[240px]"
                     >
                        <div className="p-4 bg-indigo-100 text-indigo-600 rounded-full group-hover:bg-indigo-600 group-hover:text-white transition-colors mb-4">
                            <Plus size={32} />
                        </div>
                        <h3 className="font-bold text-indigo-800 text-lg uppercase">Agregar Área</h3>
                     </button>
                 )}

                 {displayAreas.map(area => {
                     const Icon = getAreaIcon(area);
                     return (
                        <div key={area} className="relative group-card">
                            <button
                                onClick={() => !isManageMode && setSelectedArea(area)}
                                className={`w-full h-full flex flex-col items-center justify-center p-8 bg-white rounded-2xl border transition-all relative overflow-hidden text-center min-h-[240px] ${
                                    isManageMode ? 'border-gray-200 opacity-90 cursor-default' : 'border-gray-200 hover:border-indigo-500 hover:shadow-xl hover:-translate-y-1'
                                }`}
                                disabled={isManageMode} // Deshabilitar navegación en modo edición
                            >
                                <div className="absolute top-0 right-0 p-8 opacity-5 transform scale-125">
                                    <Icon size={120} />
                                </div>

                                <div className="p-4 bg-indigo-50 text-indigo-600 rounded-full mb-4 z-10 shadow-sm relative">
                                    <Icon size={32} />
                                </div>

                                <h3 className="font-bold text-gray-800 text-lg z-10 break-words w-full px-2 uppercase">
                                    {area}
                                </h3>
                                {!isManageMode && (
                                    <p className="text-xs text-gray-400 mt-2 z-10 font-medium bg-gray-50 px-3 py-1 rounded-full border border-gray-100">
                                        Acceso Autorizado
                                    </p>
                                )}
                            </button>

                            {/* CONTROLES DE EDICIÓN (OVERLAY) */}
                            {isManageMode && (
                                <div className="absolute top-3 right-3 flex gap-2 z-20">
                                    <button 
                                        onClick={() => { setInputName(area); setShowRenameModal(area); }}
                                        className="p-2 bg-white text-indigo-600 rounded-lg shadow-md border border-gray-200 hover:bg-indigo-50 hover:border-indigo-300 transition-all"
                                        title="Renombrar"
                                    >
                                        <Edit2 size={16} />
                                    </button>
                                    <button 
                                        onClick={() => setShowDeleteModal(area)}
                                        className="p-2 bg-white text-red-600 rounded-lg shadow-md border border-gray-200 hover:bg-red-50 hover:border-red-300 transition-all"
                                        title="Eliminar"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            )}
                        </div>
                     );
                 })}
            </div>
        ) : (
            /* VISTA NIVEL 2: CONTENIDO POR PESTAÑA */
            <div className="space-y-8 animate-in fade-in duration-500">
                 {groupedDocs.length === 0 ? (
                     <div className="text-center py-12 bg-white rounded-xl border border-dashed border-gray-200 shadow-sm">
                         <div className="flex justify-center mb-4">
                             <div className="bg-gray-50 p-4 rounded-full">
                                {viewTab === 'active' ? (
                                    <FolderOpen className="text-gray-300" size={32} />
                                ) : (
                                    <Archive className="text-gray-300" size={32} />
                                )}
                             </div>
                         </div>
                         <h3 className="text-lg font-bold text-gray-700">
                             {viewTab === 'active' ? 'No hay documentos vigentes' : 'No hay historial de caducos'}
                         </h3>
                         <p className="text-gray-400 text-sm mt-1">
                             {viewTab === 'active' 
                                ? 'No se encontraron procedimientos publicados en esta sección.' 
                                : 'No existen versiones obsoletas en el archivo histórico.'}
                         </p>
                     </div>
                 ) : (
                    groupedDocs.map((group, index) => (
                        <div key={group.folder ? group.folder.id : 'orphaned'} className={`bg-white rounded-xl shadow-sm border overflow-hidden ${viewTab === 'history' ? 'border-gray-200 bg-gray-50/30' : 'border-gray-100'}`}>
                            <div className={`px-6 py-4 border-b flex items-center ${viewTab === 'history' ? 'bg-gray-100 border-gray-200 text-gray-500' : 'bg-gray-50/80 border-gray-100 text-gray-800'}`}>
                                <FolderIcon className={`${viewTab === 'history' ? 'text-gray-400' : 'text-indigo-500'} mr-3`} size={20} fill="currentColor" fillOpacity={0.2} />
                                <h3 className="font-bold text-base uppercase tracking-wide">
                                    {group.folder ? group.folder.name : 'Documentación General'}
                                </h3>
                                <span className="ml-auto text-xs font-bold bg-white px-2 py-0.5 rounded border border-gray-200 text-gray-500">
                                    {group.docs.length}
                                </span>
                            </div>

                            <div className="divide-y divide-gray-50">
                                {group.docs.map(proc => {
                                    // Visual Styling para Caducos
                                    const isExpired = viewTab === 'history';

                                    return (
                                        <div 
                                            key={proc.$id} 
                                            className={`flex items-center justify-between p-4 transition-colors group ${
                                                isExpired 
                                                ? 'hover:bg-gray-100 grayscale opacity-80 hover:opacity-100' 
                                                : 'hover:bg-indigo-50/30'
                                            }`}
                                        >
                                            <Link to={`/procedure/${proc.$id}`} className="flex items-center space-x-4 flex-1">
                                                <div className={`p-2 rounded-lg border shadow-sm transition-all ${
                                                    isExpired 
                                                    ? 'bg-gray-100 text-gray-500 border-gray-200' 
                                                    : 'bg-white text-gray-400 border-gray-100 group-hover:border-indigo-200 group-hover:text-indigo-600'
                                                }`}>
                                                    <FileText size={18} />
                                                </div>
                                                <div>
                                                    <h4 className={`font-bold text-sm ${isExpired ? 'text-gray-600' : 'text-gray-700 group-hover:text-indigo-800'}`}>
                                                        {proc.name}
                                                    </h4>
                                                    <div className="flex items-center space-x-2 mt-0.5">
                                                        <span className="text-[10px] font-mono bg-gray-100 text-gray-500 px-1.5 rounded border border-gray-200">{proc.code}</span>

                                                        {/* STATUS BADGE */}
                                                        {isExpired ? (
                                                            <span className="text-[10px] px-1.5 py-0.5 rounded font-bold uppercase bg-red-100 text-red-700 border border-red-200">
                                                                OBSOLETO
                                                            </span>
                                                        ) : (
                                                            <span className={`text-[10px] px-1.5 py-0.5 rounded font-bold uppercase ${proc.status === 'Vigente' ? 'bg-emerald-50 text-emerald-700 border border-emerald-100' : 'bg-amber-50 text-amber-700'}`}>
                                                                {proc.status}
                                                            </span>
                                                        )}

                                                        <span className="text-[10px] text-gray-400">v{proc.version}</span>
                                                    </div>
                                                </div>
                                            </Link>

                                            <div className="flex items-center gap-2">
                                                {proc.attachmentUrl && proc.attachmentUrl !== '#' && (
                                                    <button 
                                                        onClick={(e) => { e.preventDefault(); setViewFile({ url: proc.attachmentUrl!, name: proc.name }); }}
                                                        className={`p-2 rounded-full transition-colors opacity-0 group-hover:opacity-100 ${isExpired ? 'text-gray-500 hover:bg-gray-200' : 'text-indigo-600 hover:bg-indigo-50'}`}
                                                        title="Previsualizar"
                                                    >
                                                        <Eye size={18} />
                                                    </button>
                                                )}
                                                <Link to={`/procedure/${proc.$id}`}>
                                                    <ChevronRight size={16} className="text-gray-300 group-hover:text-indigo-500" />
                                                </Link>
                                            </div>
                                        </div>
                                    );
                                })}
                            </div>
                        </div>
                    ))
                 )}
            </div>
        )}
      </div>

      {viewFile && (
        <FileViewerModal 
            fileUrl={viewFile.url} 
            fileName={viewFile.name} 
            onClose={() => setViewFile(null)} 
        />
      )}

      {/* --- MODALES DE ADMINISTRACIÓN --- */}

      {/* MODAL CREAR */}
      {showAddModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
              <div className="bg-white rounded-xl shadow-2xl max-w-sm w-full p-6 animate-in zoom-in duration-200">
                  <h3 className="text-lg font-bold text-gray-900 mb-4 flex items-center">
                      <Plus size={20} className="mr-2 text-indigo-600" /> Nueva Área
                  </h3>
                  <input 
                      type="text" 
                      value={inputName}
                      onChange={(e) => setInputName(e.target.value)}
                      placeholder="NOMBRE DEL DEPARTAMENTO"
                      className="w-full p-3 border border-gray-300 rounded-lg mb-4 outline-none focus:ring-2 focus:ring-indigo-500 uppercase"
                      autoFocus
                  />
                  <div className="flex gap-2 justify-end">
                      <button onClick={() => setShowAddModal(false)} className="px-4 py-2 text-gray-500 font-bold hover:bg-gray-100 rounded-lg">Cancelar</button>
                      <button 
                        onClick={handleCreateArea} 
                        disabled={processing || !inputName.trim()}
                        className="px-4 py-2 bg-indigo-600 text-white font-bold rounded-lg hover:bg-indigo-700 disabled:opacity-50"
                      >
                          {processing ? 'Creando...' : 'Crear'}
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* MODAL RENOMBRAR */}
      {showRenameModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
              <div className="bg-white rounded-xl shadow-2xl max-w-sm w-full p-6 animate-in zoom-in duration-200">
                  <h3 className="text-lg font-bold text-gray-900 mb-2 flex items-center">
                      <Edit2 size={20} className="mr-2 text-indigo-600" /> Renombrar Área
                  </h3>
                  <p className="text-xs text-amber-600 mb-4 bg-amber-50 p-2 rounded border border-amber-100">
                      <strong>¡Atención!</strong> Esto actualizará todos los documentos y usuarios vinculados a "{showRenameModal}".
                  </p>
                  <input 
                      type="text" 
                      value={inputName}
                      onChange={(e) => setInputName(e.target.value)}
                      className="w-full p-3 border border-gray-300 rounded-lg mb-4 outline-none focus:ring-2 focus:ring-indigo-500 uppercase"
                  />
                  <div className="flex gap-2 justify-end">
                      <button onClick={() => setShowRenameModal(null)} className="px-4 py-2 text-gray-500 font-bold hover:bg-gray-100 rounded-lg">Cancelar</button>
                      <button 
                        onClick={handleRenameArea} 
                        disabled={processing || !inputName.trim() || inputName === showRenameModal}
                        className="px-4 py-2 bg-indigo-600 text-white font-bold rounded-lg hover:bg-indigo-700 disabled:opacity-50"
                      >
                          {processing ? 'Guardando...' : 'Guardar Cambios'}
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* MODAL ELIMINAR */}
      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
              <div className="bg-white rounded-xl shadow-2xl max-w-sm w-full p-6 animate-in zoom-in duration-200 border-t-4 border-red-500">
                  <div className="flex justify-center mb-4 text-red-500"><AlertTriangle size={48} /></div>
                  <h3 className="text-lg font-bold text-gray-900 text-center mb-2">¿Eliminar "{showDeleteModal}"?</h3>
                  <p className="text-sm text-gray-600 text-center mb-6">
                      Esta acción eliminará el área del catálogo. Si existen usuarios o documentos vinculados, podrían quedar sin clasificación.
                  </p>
                  <div className="flex gap-2 justify-center">
                      <button onClick={() => setShowDeleteModal(null)} className="px-4 py-2 border border-gray-300 text-gray-700 font-bold hover:bg-gray-50 rounded-lg">Cancelar</button>
                      <button 
                        onClick={handleDeleteArea} 
                        disabled={processing}
                        className="px-4 py-2 bg-red-600 text-white font-bold rounded-lg hover:bg-red-700 disabled:opacity-50"
                      >
                          {processing ? 'Eliminando...' : 'Sí, Eliminar'}
                      </button>
                  </div>
              </div>
          </div>
      )}

    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { appwriteService, normalizeString } from '../services/appwriteService';
import { Procedure, Folder, Area } from '../types';
import { Search, Folder as FolderIcon, ChevronRight, FileText, ArrowLeft, Grid, Layers, Archive, Box, Activity, ClipboardCheck, Truck, Monitor, Users, ShoppingBag, FolderOpen, Eye, Settings, Plus, Edit2, Trash2, X, Save, AlertTriangle, CheckCircle, Info, Warehouse, RotateCcw, Shield, Briefcase, Wrench, Clock, CornerUpLeft } from 'lucide-react';
import { Link } from 'react-router-dom';
import { FileViewerModal } from '../components/FileViewerModal';

