};

function RefreshIcon(props: any) { return <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" {...props}><path d="M21 12a9 9 0 0 0-9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"/><path d="M3 3v5h5"/><path d="M3 12a9 9 0 0 0 9 9 9.75 9.75 0 0 0 6.74-2.74L21 16"/><path d="M16 16h5v5"/></svg>; }

const Toast = ({ message, type, onClose }: { message: string, type: 'success' | 'error', onClose: () => void }) => (
    <div className={`fixed bottom-6 right-6 z-[100] px-4 py-3 rounded-lg shadow-lg flex items-center gap-3 animate-in slide-in-from-bottom duration-300 border ${type === 'success' ? 'bg-emerald-50 border-emerald-200 text-emerald-800' : 'bg-red-50 border-red-200 text-red-800'}`}>
        {type === 'success' ? <CheckCircle size={20} className="text-emerald-600" /> : <AlertTriangle size={20} className="text-red-600" />}
        <span className="font-medium text-sm">{message}</span>
        <button onClick={onClose} className="ml-2 hover:opacity-70"><X size={16} /></button>
    </div>
);

export const Catalog: React.FC = () => {
  const { user } = useAuth();

  // Estados de Navegación
  const [selectedArea, setSelectedArea] = useState<string | null>(null);
  const [currentFolder, setCurrentFolder] = useState<Folder | null>(null); // NAVEGACIÓN: Carpeta actual
  const [searchTerm, setSearchTerm] = useState('');

  // Estados de Filtro (Vigente vs Histórico)
  const [viewTab, setViewTab] = useState<'active' | 'history'>('active');

  // Datos
  const [areaProcedures, setAreaProcedures] = useState<Procedure[]>([]);
  const [areaFolders, setAreaFolders] = useState<Folder[]>([]);
  const [loading, setLoading] = useState(false);
  const [availableAreas, setAvailableAreas] = useState<string[]>([]);

  // Estados Admin
  const [isManageMode, setIsManageMode] = useState(false);
  const [showAddModal, setShowAddModal] = useState(false);
  const [showRenameModal, setShowRenameModal] = useState<string | null>(null);
  const [showDeleteModal, setShowDeleteModal] = useState<string | null>(null);
  const [inputName, setInputName] = useState('');
  const [processing, setProcessing] = useState(false);

  // UI
  const [toast, setToast] = useState<{msg: string, type: 'success'|'error'} | null>(null);
  const [viewFile, setViewFile] = useState<{url: string, name: string} | null>(null);

  const isAdmin = user?.role === 'admin';
  const isSingleAreaUser = !isAdmin && user?.allowedAreas.length === 1;

  const showToast = (msg: string, type: 'success' | 'error') => {
      setToast({ msg, type });
      setTimeout(() => setToast(null), 4000);
  };

  const refreshAreas = async () => {
      const dbAreas = await appwriteService.getAllAreas();
      setAvailableAreas(dbAreas);
  };

  useEffect(() => {
    refreshAreas();
  }, []);

  useEffect(() => {
      if (isSingleAreaUser && !selectedArea && user?.allowedAreas[0]) {
          setSelectedArea(user.allowedAreas[0]);
      }
  }, [isSingleAreaUser, selectedArea, user]);

  const displayAreas = availableAreas.filter(area => {
      if (isAdmin) return true;
      const normalizedArea = normalizeString(area);
      return user?.allowedAreas.some(allowed => normalizeString(allowed) === normalizedArea);
  });

  // Carga inicial (Búsqueda global)
  useEffect(() => {
    if (searchTerm.length > 2 && user) {
        setLoading(true);
        setCurrentFolder(null); // Reset folder on global search
        appwriteService.getProcedures(user, searchTerm).then(docs => {
            setAreaProcedures(docs);
            setLoading(false);
        });
    }
  }, [searchTerm, user]);

  // Cargar contenido de Área
  useEffect(() => {
      const loadAreaContent = async () => {
          if (user && selectedArea && !searchTerm) {
              setLoading(true);
              try {
                  const [folders, docs] = await Promise.all([
                      appwriteService.getFolders(selectedArea),
                      appwriteService.getProcedures(user, '', selectedArea)
                  ]);
                  setAreaFolders(folders);
                  setAreaProcedures(docs);
              } catch (e) {
                  console.error(e);
              } finally {
                  setLoading(false);
              }
          }
      };
      loadAreaContent();
  }, [selectedArea, user, searchTerm]);

  // Manejo del botón "Atrás" inteligente
  const handleBack = () => {
      setSearchTerm('');

      if (currentFolder) {
          // Si estamos dentro de una carpeta, subimos al nivel raíz del área
          setCurrentFolder(null);
      } else {
          // Si estamos en raíz del área, volvemos al selector de áreas (si aplica)
          if (!isSingleAreaUser) {
              setSelectedArea(null);
              setAreaProcedures([]);
              setAreaFolders([]);
          }
      }
  };

  // --- LOGICA DE RENDERIZADO DE CARPETAS Y ARCHIVOS ---

  // 1. Filtrar por STATUS (Vigente vs Histórico)
  const filteredByStatus = areaProcedures.filter(proc => {
      const status = (proc.status || 'Vigente').toString();
      if (viewTab === 'active') return status !== 'Caduco' && status !== 'Obsoleto';
      return status === 'Caduco' || status === 'Obsoleto';
  });

  // 2. Separar lo que se muestra en la vista actual (Raíz vs Carpeta)
  let visibleFolders: Folder[] = [];
  let visibleDocs: Procedure[] = [];

  if (selectedArea && !searchTerm) {
      if (currentFolder) {
          // VISTA DENTRO DE CARPETA:
          // Solo documentos que tengan este folder_id
          visibleFolders = []; // No anidamos carpetas por ahora (estructura plana visual)
          visibleDocs = filteredByStatus.filter(p => p.folder_id === currentFolder.id);
      } else {
          // VISTA RAÍZ DEL ÁREA:
          // Carpetas del área
          visibleFolders = areaFolders;
          // Documentos sueltos (folder_id null) O documentos cuyo folder_id no existe en published_folders (huérfanos)
          const validFolderIds = areaFolders.map(f => f.id);
          visibleDocs = filteredByStatus.filter(p => !p.folder_id || !validFolderIds.includes(p.folder_id));
      }
  } else if (searchTerm) {
      // EN BÚSQUEDA: Todo plano
      visibleDocs = areaProcedures; // Ya vienen filtrados por texto
  }

  // Helper para contar elementos activos dentro de una carpeta (para el badge)
  const getFolderCount = (folderId: string) => {
      return areaProcedures.filter(p => p.folder_id === folderId && p.status !== 'Caduco').length;
  };

  const isSearching = searchTerm.length > 0;
  const showBackButton = isSearching || (selectedArea && (!isSingleAreaUser || currentFolder));

  const getAreaIcon = (areaName: string) => {
      const upperName = areaName.toUpperCase();
      return AREA_ICONS[upperName] || Box;
  };

  // --- ADMIN HANDLERS ---
  const handleCreateArea = async () => {
      if (!inputName.trim()) return;
      setProcessing(true);
      const success = await appwriteService.createArea(inputName.trim());
      if (success) { await refreshAreas(); showToast(`Área creada`, 'success'); setShowAddModal(false); setInputName(''); }
      setProcessing(false);
  };
  const handleRenameArea = async () => {
      if (!showRenameModal || !inputName.trim()) return;
      setProcessing(true);
      const success = await appwriteService.renameArea(showRenameModal, inputName.trim());
      if (success) { await refreshAreas(); showToast(`Área renombrada`, 'success'); setShowRenameModal(null); setInputName(''); }
      setProcessing(false);
  };
  const handleDeleteArea = async () => {
      if (!showDeleteModal) return;
      setProcessing(true);
      const success = await appwriteService.deleteArea(showDeleteModal);
      if (success) { await refreshAreas(); showToast(`Área eliminada`, 'success'); setShowDeleteModal(null); }
      setProcessing(false);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 min-h-[600px] flex flex-col relative">
      {toast && <Toast message={toast.msg} type={toast.type} onClose={() => setToast(null)} />}

      {/* HEADER & NAVIGATION */}
      <div className="p-6 border-b border-gray-100 flex flex-col gap-4 bg-gray-50/30">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
            <div className="flex items-center w-full md:w-auto">
                {showBackButton && (
                    <button 
                        onClick={handleBack}
                        className="mr-3 p-2 hover:bg-white rounded-full text-indigo-700 transition-colors shadow-sm border border-transparent hover:border-gray-200"
                        title="Atrás"
                    >
                        <ArrowLeft size={20} />
                    </button>
                )}

                <div>
                    {isSearching ? (
                        <h2 className="text-xl font-bold text-gray-800">Buscando: "{searchTerm}"</h2>
                    ) : selectedArea ? (
                        <div>
                             <p className="text-xs text-gray-400 uppercase font-bold tracking-wider mb-0.5 flex items-center">
                                 {selectedArea}
                                 {currentFolder && <ChevronRight size={12} className="mx-1" />}
                                 {currentFolder && <span className="text-indigo-600">{currentFolder.name}</span>}
                             </p>
                             <h2 className="text-xl font-bold text-gray-800 flex items-center uppercase">
                                 {currentFolder ? currentFolder.name : 'Directorio Principal'}
                             </h2>
                        </div>
                    ) : (
                        <div className="flex items-center text-gray-800 font-bold text-lg">
                            <Grid size={20} className="mr-2 text-indigo-600" />
                            Catálogo de Procesos
                        </div>
                    )}
                </div>
            </div>

            <div className="flex items-center gap-3 w-full md:w-auto">
                <div className="relative flex-1 md:w-64">
                    <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={20} />
                    <input 
                        type="text" 
                        placeholder="Buscar globalmente..." 
                        className="w-full pl-10 pr-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-100 focus:border-indigo-400 outline-none transition-all shadow-sm"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>

                {isAdmin && !selectedArea && !isSearching && (
                    <button 
                        onClick={() => setIsManageMode(!isManageMode)}
                        className={`p-2.5 rounded-lg border transition-all ${isManageMode ? 'bg-indigo-600 text-white' : 'bg-white text-gray-500'}`}
                    >
                        <Settings size={20} className={isManageMode ? 'animate-spin-slow' : ''} />
                    </button>
                )}
            </div>
        </div>
      </div>

      {/* BODY */}
      <div className="flex-1 p-6 bg-gray-50/10 flex flex-col">

        {/* TABS (SOLO SI NO BUSCAMOS) */}
        {selectedArea && !isSearching && !loading && (
            <div className="flex justify-between items-center mb-6">
                <div className="flex space-x-1 bg-gray-100/50 p-1 rounded-lg border border-gray-200">
                    <button onClick={() => setViewTab('active')} className={`px-4 py-2 text-sm font-bold rounded-md transition-all flex items-center ${viewTab === 'active' ? 'bg-white text-indigo-700 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>
                        <CheckCircle size={16} className="mr-2" /> VIGENTES
                    </button>
                    <button onClick={() => setViewTab('history')} className={`px-4 py-2 text-sm font-bold rounded-md transition-all flex items-center ${viewTab === 'history' ? 'bg-white text-gray-700 shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}>
                        <Clock size={16} className="mr-2" /> CADUCOS
                    </button>
                </div>

                {currentFolder && (
                    <button onClick={handleBack} className="text-sm font-bold text-indigo-600 hover:underline flex items-center">
                        <CornerUpLeft size={16} className="mr-1" /> Subir Nivel
                    </button>
                )}
            </div>
        )}

        {loading ? (
             <div className="p-12 text-center text-gray-400 flex flex-col items-center">
                 <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-600 mb-4"></div>
                 Sincronizando...
             </div>
        ) : !selectedArea && !isSearching ? (
            /* VISTA SELECCIÓN DE ÁREA (GRID) */
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                 {isManageMode && (
                     <button onClick={() => { setInputName(''); setShowAddModal(true); }} className="flex flex-col items-center justify-center p-8 bg-white rounded-2xl border-2 border-dashed border-indigo-300 hover:bg-indigo-50 transition-all min-h-[240px] text-indigo-600 font-bold">
                        <Plus size={32} className="mb-2" /> AGREGAR ÁREA
                     </button>
                 )}
                 {displayAreas.map(area => {
                     const Icon = getAreaIcon(area);
                     return (
                        <div key={area} className="relative group-card">
                            <button
                                onClick={() => !isManageMode && setSelectedArea(area)}
                                className={`w-full h-full flex flex-col items-center justify-center p-8 bg-white rounded-2xl border transition-all relative overflow-hidden text-center min-h-[240px] ${isManageMode ? 'border-gray-200 opacity-90' : 'border-gray-200 hover:border-indigo-500 hover:shadow-xl hover:-translate-y-1'}`}
                                disabled={isManageMode}
                            >
                                <div className="absolute top-0 right-0 p-8 opacity-5 transform scale-125"><Icon size={120} /></div>
                                <div className="p-4 bg-indigo-50 text-indigo-600 rounded-full mb-4 z-10 shadow-sm relative"><Icon size={32} /></div>
                                <h3 className="font-bold text-gray-800 text-lg z-10 break-words w-full px-2 uppercase">{area}</h3>
                            </button>
                            {isManageMode && (
                                <div className="absolute top-3 right-3 flex gap-2 z-20">
                                    <button onClick={() => { setInputName(area); setShowRenameModal(area); }} className="p-2 bg-white text-indigo-600 rounded shadow border"><Edit2 size={16} /></button>
                                    <button onClick={() => setShowDeleteModal(area)} className="p-2 bg-white text-red-600 rounded shadow border"><Trash2 size={16} /></button>
                                </div>
                            )}
                        </div>
                     );
                 })}
            </div>
        ) : (
            /* VISTA DE CONTENIDO (CARPETAS + ARCHIVOS) */
            <div className="space-y-8 animate-in fade-in duration-300">

                {/* 1. GRID DE CARPETAS (SOLO EN RAÍZ Y SI NO ES BÚSQUEDA) */}
                {visibleFolders.length > 0 && !currentFolder && !isSearching && (
                    <div>
                        <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-4 flex items-center">
                            <FolderIcon size={14} className="mr-2" /> Carpetas
                        </h3>
                        <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-4">
                            {visibleFolders.map(folder => {
                                const count = getFolderCount(folder.id);
                                return (
                                    <button
                                        key={folder.id}
                                        onClick={() => setCurrentFolder(folder)}
                                        className="bg-white p-4 rounded-xl border border-gray-200 hover:border-indigo-400 hover:shadow-md transition-all text-left group flex flex-col justify-between h-32 relative overflow-hidden"
                                    >
                                        <div className="absolute top-0 right-0 p-2 opacity-5 group-hover:opacity-10 transition-opacity">
                                            <FolderIcon size={64} className="text-indigo-900" />
                                        </div>
                                        <div className="p-2 bg-indigo-50 text-indigo-600 rounded-lg w-fit group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                                            <FolderIcon size={20} fill="currentColor" fillOpacity={0.2} />
                                        </div>
                                        <div>
                                            <h4 className="font-bold text-gray-800 text-sm truncate uppercase group-hover:text-indigo-700">{folder.name}</h4>
                                            <p className="text-xs text-gray-400">{count} documentos</p>
                                        </div>
                                    </button>
                                );
                            })}
                        </div>
                    </div>
                )}

                {/* 2. LISTA DE ARCHIVOS */}
                <div>
                    {(visibleFolders.length > 0 && visibleDocs.length > 0) && (
                        <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-4 flex items-center mt-8">
                            <FileText size={14} className="mr-2" /> Archivos
                        </h3>
                    )}

                    {visibleDocs.length === 0 ? (
                        <div className="text-center py-12 bg-white rounded-xl border border-dashed border-gray-200">
                            <div className="bg-gray-50 p-4 rounded-full inline-block mb-3">
                                {viewTab === 'active' ? <FolderOpen className="text-gray-300" size={32} /> : <Archive className="text-gray-300" size={32} />}
                            </div>
                            <p className="text-gray-500 font-medium">Esta carpeta está vacía.</p>
                        </div>
                    ) : (
                        <div className="grid grid-cols-1 gap-3">
                            {visibleDocs.map(proc => {
                                const isExpired = viewTab === 'history';
                                return (
                                    <div key={proc.$id} className={`flex items-center justify-between p-4 bg-white rounded-lg border transition-all group ${isExpired ? 'border-gray-200 hover:bg-gray-50 opacity-75' : 'border-gray-100 hover:border-indigo-300 hover:shadow-md'}`}>
                                        <Link to={`/procedure/${proc.$id}`} className="flex items-center space-x-4 flex-1">
                                            <div className={`p-2.5 rounded-lg border shadow-sm ${isExpired ? 'bg-gray-100 text-gray-400' : 'bg-white text-indigo-600 border-indigo-50 group-hover:bg-indigo-600 group-hover:text-white transition-colors'}`}>
                                                <FileText size={20} />
                                            </div>
                                            <div>
                                                <h4 className={`font-bold text-sm ${isExpired ? 'text-gray-500 line-through' : 'text-gray-800 group-hover:text-indigo-800'}`}>{proc.name}</h4>
                                                <div className="flex items-center space-x-2 mt-1">
                                                    <span className="text-[10px] font-mono bg-gray-100 text-gray-500 px-1.5 rounded border border-gray-200">{proc.code}</span>
                                                    {!isExpired && <span className={`text-[10px] px-1.5 py-0.5 rounded font-bold uppercase ${proc.status === 'Vigente' ? 'bg-emerald-50 text-emerald-700' : 'bg-amber-50 text-amber-700'}`}>{proc.status}</span>}
                                                    {isExpired && <span className="text-[10px] px-1.5 py-0.5 rounded font-bold uppercase bg-red-50 text-red-700">OBSOLETO</span>}
                                                    <span className="text-[10px] text-gray-400">v{proc.version}</span>
                                                </div>
                                            </div>
                                        </Link>
                                        <div className="flex items-center gap-2">
                                            {proc.attachmentUrl && proc.attachmentUrl !== '#' && (
                                                <button onClick={() => setViewFile({ url: proc.attachmentUrl!, name: proc.name })} className="p-2 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors" title="Previsualizar">
                                                    <Eye size={18} />
                                                </button>
                                            )}
                                            <Link to={`/procedure/${proc.$id}`}><ChevronRight size={18} className="text-gray-300 group-hover:text-indigo-500" /></Link>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>
            </div>
        )}
      </div>

      {viewFile && <FileViewerModal fileUrl={viewFile.url} fileName={viewFile.name} onClose={() => setViewFile(null)} />}

      {/* ADMIN MODALS (SIMPLIFICADOS) */}
      {showAddModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
              <div className="bg-white p-6 rounded-xl shadow-xl w-full max-w-sm">
                  <h3 className="font-bold mb-4">Nueva Área</h3>
                  <input value={inputName} onChange={e => setInputName(e.target.value)} className="w-full border p-2 rounded mb-4 uppercase" autoFocus />
                  <div className="flex justify-end gap-2"><button onClick={() => setShowAddModal(false)} className="px-4 py-2">Cancelar</button><button onClick={handleCreateArea} className="px-4 py-2 bg-indigo-600 text-white rounded">Crear</button></div>
              </div>
          </div>
      )}
      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
              <div className="bg-white p-6 rounded-xl shadow-xl w-full max-w-sm border-t-4 border-red-500">
                  <h3 className="font-bold mb-2">¿Eliminar {showDeleteModal}?</h3>
                  <p className="text-sm text-gray-500 mb-4">Esta acción no se puede deshacer.</p>
                  <div className="flex justify-end gap-2"><button onClick={() => setShowDeleteModal(null)} className="px-4 py-2">Cancelar</button><button onClick={handleDeleteArea} className="px-4 py-2 bg-red-600 text-white rounded">Eliminar</button></div>
              </div>
          </div>
      )}
      {showRenameModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
              <div className="bg-white p-6 rounded-xl shadow-xl w-full max-w-sm">
                  <h3 className="font-bold mb-4">Renombrar Área</h3>
                  <input value={inputName} onChange={e => setInputName(e.target.value)} className="w-full border p-2 rounded mb-4 uppercase" />
                  <div className="flex justify-end gap-2"><button onClick={() => setShowRenameModal(null)} className="px-4 py-2">Cancelar</button><button onClick={handleRenameArea} className="px-4 py-2 bg-indigo-600 text-white rounded">Guardar</button></div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { appwriteService, normalizeString } from '../services/appwriteService';
import { Procedure, Folder, Area } from '../types';
import { Search, Folder as FolderIcon, ChevronRight, FileText, ArrowLeft, Grid, Layers, Archive, Box, Activity, ClipboardCheck, Truck, Monitor, Users, ShoppingBag, FolderOpen, Eye, Settings, Plus, Edit2, Trash2, X, Save, AlertTriangle, CheckCircle, Info, Warehouse, RotateCcw, Shield, Briefcase, Wrench, Clock, CornerUpLeft } from 'lucide-react';
import { Link } from 'react-router-dom';
import { FileViewerModal } from '../components/FileViewerModal';

// Mapeo de Iconos por Área
const AREA_ICONS: {[key: string]: any} = {
  "PROYECTOS Y MEJORA CONTINUA": Activity,
  "MENSAJERIA Y DISTRIBUCION": Truck,
  "MENSAJERÍA Y DISTRIBUCIÓN": Truck,
  "CALIDAD": ClipboardCheck,
  "ALMACEN C": Box,
  "ALMACEN F": Box,
  "CENTRO DE DISTRIBUCIÓN": Warehouse,
  "CENTRO DE DISTRIBUCION": Warehouse,
  "EMPAQUE RETAIL": ShoppingBag,
  "EMPAQUE TV": ShoppingBag,
  "DEVOLUCIONES": Archive,
  "INVENTARIOS": Layers,
  "RECIBO": ArrowLeft,
  "REACONDICIONADO": RefreshIcon,
  "MAQUILA": Layers,
  "TECNOLOGÍAS DE LA INFORMACIÓN": Monitor,
  "TECNOLOGIAS DE LA INFORMACION": Monitor,
  "RECURSOS HUMANOS": Users,
  "LOGÍSTICA INVERSA": RotateCcw,
  "LOGISTICA INVERSA": RotateCcw,
  "MANTENIMIENTO": Wrench,
  "SEGURIDAD": Shield,
  "SEGURIDAD PATRIMONIAL": Shield,
  "COMPRAS": Briefcase,
  "VENTAS": Briefcase,
  "DIRECCIÓN": Briefcase,
  "DIRECCION": Briefcase,
  "ADMINISTRACIÓN": Briefcase,
  "ADMINISTRACION": Briefcase
};

function RefreshIcon(props: any) { return <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" {...props}><path d="M21 12a9 9 0 0 0-9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"/><path d="M3 3v5h5"/><path d="M3 12a9 9 0 0 0 9 9 9.75 9.75 0 0 0 6.74-2.74L21 16"/><path d="M16 16h5v5"/></svg>; }

const Toast = ({ message, type, onClose }: { message: string, type: 'success' | 'error', onClose: () => void }) => (
    <div className={`fixed bottom-6 right-6 z-[100] px-4 py-3 rounded-lg shadow-lg flex items-center gap-3 animate-in slide-in-from-bottom duration-300 border ${type === 'success' ? 'bg-emerald-50 border-emerald-200 text-emerald-800' : 'bg-red-50 border-red-200 text-red-800'}`}>
        {type === 'success' ? <CheckCircle size={20} className="text-emerald-600" /> : <AlertTriangle size={20} className="text-red-600" />}
        <span className="font-medium text-sm">{message}</span>
        <button onClick={onClose} className="ml-2 hover:opacity-70"><X size={16} /></button>
    </div>
);

export const Catalog: React.FC = () => {
  const { user } = useAuth();

  // Estados de Navegación
  const [selectedArea, setSelectedArea] = useState<string | null>(null);
  const [currentFolder, setCurrentFolder] = useState<Folder | null>(null); // NAVEGACIÓN: Carpeta actual
  const [searchTerm, setSearchTerm] = useState('');

  // Estados de Filtro (Vigente vs Histórico)
  const [viewTab, setViewTab] = useState<'active' | 'history'>('active');

  // Datos
  const [areaProcedures, setAreaProcedures] = useState<Procedure[]>([]);
  const [areaFolders, setAreaFolders] = useState<Folder[]>([]);
  const [loading, setLoading] = useState(false);
  const [availableAreas, setAvailableAreas] = useState<string[]>([]);

  // Estados Admin
  const [isManageMode, setIsManageMode] = useState(false);
  const [showAddModal, setShowAddModal] = useState(false);
  const [showRenameModal, setShowRenameModal] = useState<string | null>(null);
  const [showDeleteModal, setShowDeleteModal] = useState<string | null>(null);
  const [inputName, setInputName] = useState('');
  const [processing, setProcessing] = useState(false);

  // UI
  const [toast, setToast] = useState<{msg: string, type: 'success'|'error'} | null>(null);
  const [viewFile, setViewFile] = useState<{url: string, name: string} | null>(null);

  const isAdmin = user?.role === 'admin';
  const isSingleAreaUser = !isAdmin && user?.allowedAreas.length === 1;

  const showToast = (msg: string, type: 'success' | 'error') => {
      setToast({ msg, type });
      setTimeout(() => setToast(null), 4000);
  };

  const refreshAreas = async () => {
      const dbAreas = await appwriteService.getAllAreas();
      setAvailableAreas(dbAreas);
  };

  useEffect(() => {
    refreshAreas();
  }, []);

  useEffect(() => {
      if (isSingleAreaUser && !selectedArea && user?.allowedAreas[0]) {
          setSelectedArea(user.allowedAreas[0]);
      }
  }, [isSingleAreaUser, selectedArea, user]);

  const displayAreas = availableAreas.filter(area => {
      if (isAdmin) return true;
      const normalizedArea = normalizeString(area);
      return user?.allowedAreas.some(allowed => normalizeString(allowed) === normalizedArea);
  });

  // Carga inicial (Búsqueda global)
  useEffect(() => {
    if (searchTerm.length > 2 && user) {
        setLoading(true);
        setCurrentFolder(null); // Reset folder on global search
        appwriteService.getProcedures(user, searchTerm).then(docs => {
            setAreaProcedures(docs);
            setLoading(false);
        });
    }
  }, [searchTerm, user]);

  // Cargar contenido de Área
  useEffect(() => {
      const loadAreaContent = async () => {
          if (user && selectedArea && !searchTerm) {
              setLoading(true);
              try {
                  const [folders, docs] = await Promise.all([
                      appwriteService.getFolders(selectedArea),
                      appwriteService.getProcedures(user, '', selectedArea)
                  ]);
                  setAreaFolders(folders);
                  setAreaProcedures(docs);
              } catch (e) {
                  console.error(e);
              } finally {
                  setLoading(false);
              }
          }
      };
      loadAreaContent();
  }, [selectedArea, user, searchTerm]);

  // Manejo del botón "Atrás" inteligente
  const handleBack = () => {
      setSearchTerm('');

      if (currentFolder) {
          // Si estamos dentro de una carpeta, subimos al nivel raíz del área
          setCurrentFolder(null);
      } else {
          // Si estamos en raíz del área, volvemos al selector de áreas (si aplica)
          if (!isSingleAreaUser) {
              setSelectedArea(null);
              setAreaProcedures([]);
              setAreaFolders([]);
          }
      }
  };

  // --- LOGICA DE RENDERIZADO DE CARPETAS Y ARCHIVOS ---

  // 1. Filtrar por STATUS (Vigente vs Histórico) con comparación robusta
  const filteredByStatus = areaProcedures.filter(proc => {
      const status = (proc.status || 'Vigente').toString().toUpperCase().trim();
      const isExpired = status === 'CADUCO' || status === 'OBSOLETO';

      if (viewTab === 'active') {
          // Mostrar TODO lo que NO sea Caduco u Obsoleto
          return !isExpired;
      } else {
          // Mostrar SOLO lo Caduco u Obsoleto
          return isExpired;
      }
  });

  // 2. Separar lo que se muestra en la vista actual (Raíz vs Carpeta)
  let visibleFolders: Folder[] = [];
  let visibleDocs: Procedure[] = [];

  if (selectedArea && !searchTerm) {
      if (currentFolder) {
          // VISTA DENTRO DE CARPETA:
          // Solo documentos que tengan este folder_id
          visibleFolders = []; // No anidamos carpetas por ahora (estructura plana visual)
          visibleDocs = filteredByStatus.filter(p => p.folder_id === currentFolder.id);
      } else {
          // VISTA RAÍZ DEL ÁREA:
          // Carpetas del área
          visibleFolders = areaFolders;
          // Documentos sueltos (folder_id null) O documentos cuyo folder_id no existe en published_folders (huérfanos)
          const validFolderIds = areaFolders.map(f => f.id);
          visibleDocs = filteredByStatus.filter(p => !p.folder_id || !validFolderIds.includes(p.folder_id));
      }
  } else if (searchTerm) {
      // EN BÚSQUEDA: Todo plano
      visibleDocs = areaProcedures; // Ya vienen filtrados por texto (Nota: Aquí no aplicamos filtro de vigencia estricto para permitir buscar históricos si el backend los trae, o podrías aplicar filteredByStatus si prefieres respetar el tab incluso en búsqueda)
  }

  // Helper para contar elementos en base al tab actual
  const getFolderCount = (folderId: string) => {
      // Cuenta usando el array FILTRADO por estado, así el badge refleja lo que verás al entrar
      return filteredByStatus.filter(p => p.folder_id === folderId).length;
  };

  const isSearching = searchTerm.length > 0;
  const showBackButton = isSearching || (selectedArea && (!isSingleAreaUser || currentFolder));

  const getAreaIcon = (areaName: string) => {
      const upperName = areaName.toUpperCase();
      return AREA_ICONS[upperName] || Box;
  };

  // --- ADMIN HANDLERS ---
  const handleCreateArea = async () => {
      if (!inputName.trim()) return;
      setProcessing(true);
      const success = await appwriteService.createArea(inputName.trim());
      if (success) { await refreshAreas(); showToast(`Área creada`, 'success'); setShowAddModal(false); setInputName(''); }
      setProcessing(false);
  };
  const handleRenameArea = async () => {
      if (!showRenameModal || !inputName.trim()) return;
      setProcessing(true);
      const success = await appwriteService.renameArea(showRenameModal, inputName.trim());
      if (success) { await refreshAreas(); showToast(`Área renombrada`, 'success'); setShowRenameModal(null); setInputName(''); }
      setProcessing(false);
  };
  const handleDeleteArea = async () => {
      if (!showDeleteModal) return;
      setProcessing(true);
      const success = await appwriteService.deleteArea(showDeleteModal);
      if (success) { await refreshAreas(); showToast(`Área eliminada`, 'success'); setShowDeleteModal(null); }
      setProcessing(false);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 min-h-[600px] flex flex-col relative">
      {toast && <Toast message={toast.msg} type={toast.type} onClose={() => setToast(null)} />}

      {/* HEADER & NAVIGATION */}
      <div className="p-6 border-b border-gray-100 flex flex-col gap-4 bg-gray-50/30">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
            <div className="flex items-center w-full md:w-auto">
                {showBackButton && (
                    <button 
                        onClick={handleBack}
                        className="mr-3 p-2 hover:bg-white rounded-full text-indigo-700 transition-colors shadow-sm border border-transparent hover:border-gray-200"
                        title="Atrás"
                    >
                        <ArrowLeft size={20} />
                    </button>
                )}

                <div>
                    {isSearching ? (
                        <h2 className="text-xl font-bold text-gray-800">Buscando: "{searchTerm}"</h2>
                    ) : selectedArea ? (
                        <div>
                             <p className="text-xs text-gray-400 uppercase font-bold tracking-wider mb-0.5 flex items-center">
                                 {selectedArea}
                                 {currentFolder && <ChevronRight size={12} className="mx-1" />}
                                 {currentFolder && <span className="text-indigo-600">{currentFolder.name}</span>}
                             </p>
                             <h2 className="text-xl font-bold text-gray-800 flex items-center uppercase">
                                 {currentFolder ? currentFolder.name : 'Directorio Principal'}
                             </h2>
                        </div>
                    ) : (
                        <div className="flex items-center text-gray-800 font-bold text-lg">
                            <Grid size={20} className="mr-2 text-indigo-600" />
                            Catálogo de Procesos
                        </div>
                    )}
                </div>
            </div>

            <div className="flex items-center gap-3 w-full md:w-auto">
                <div className="relative flex-1 md:w-64">
                    <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={20} />
                    <input 
                        type="text" 
                        placeholder="Buscar globalmente..." 
                        className="w-full pl-10 pr-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-100 focus:border-indigo-400 outline-none transition-all shadow-sm"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>

                {isAdmin && !selectedArea && !isSearching && (
                    <button 
                        onClick={() => setIsManageMode(!isManageMode)}
                        className={`p-2.5 rounded-lg border transition-all ${isManageMode ? 'bg-indigo-600 text-white' : 'bg-white text-gray-500'}`}
                    >
                        <Settings size={20} className={isManageMode ? 'animate-spin-slow' : ''} />
                    </button>
                )}
            </div>
        </div>
      </div>

      {/* BODY */}
      <div className="flex-1 p-6 bg-gray-50/10 flex flex-col">

        {/* TABS (SOLO SI NO BUSCAMOS) */}
        {selectedArea && !isSearching && !loading && (
            <div className="flex justify-between items-center mb-6">
                <div className="flex space-x-1 bg-gray-100/50 p-1 rounded-lg border border-gray-200">
                    <button onClick={() => setViewTab('active')} className={`px-4 py-2 text-sm font-bold rounded-md transition-all flex items-center ${viewTab === 'active' ? 'bg-white text-indigo-700 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>
                        <CheckCircle size={16} className="mr-2" /> VIGENTES
                    </button>
                    <button onClick={() => setViewTab('history')} className={`px-4 py-2 text-sm font-bold rounded-md transition-all flex items-center ${viewTab === 'history' ? 'bg-white text-gray-700 shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}>
                        <Clock size={16} className="mr-2" /> CADUCOS
                    </button>
                </div>

                {currentFolder && (
                    <button onClick={handleBack} className="text-sm font-bold text-indigo-600 hover:underline flex items-center">
                        <CornerUpLeft size={16} className="mr-1" /> Subir Nivel
                    </button>
                )}
            </div>
        )}

        {loading ? (
             <div className="p-12 text-center text-gray-400 flex flex-col items-center">
                 <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-600 mb-4"></div>
                 Sincronizando...
             </div>
        ) : !selectedArea && !isSearching ? (
            /* VISTA SELECCIÓN DE ÁREA (GRID) */
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                 {isManageMode && (
                     <button onClick={() => { setInputName(''); setShowAddModal(true); }} className="flex flex-col items-center justify-center p-8 bg-white rounded-2xl border-2 border-dashed border-indigo-300 hover:bg-indigo-50 transition-all min-h-[240px] text-indigo-600 font-bold">
                        <Plus size={32} className="mb-2" /> AGREGAR ÁREA
                     </button>
                 )}
                 {displayAreas.map(area => {
                     const Icon = getAreaIcon(area);
                     return (
                        <div key={area} className="relative group-card">
                            <button
                                onClick={() => !isManageMode && setSelectedArea(area)}
                                className={`w-full h-full flex flex-col items-center justify-center p-8 bg-white rounded-2xl border transition-all relative overflow-hidden text-center min-h-[240px] ${isManageMode ? 'border-gray-200 opacity-90' : 'border-gray-200 hover:border-indigo-500 hover:shadow-xl hover:-translate-y-1'}`}
                                disabled={isManageMode}
                            >
                                <div className="absolute top-0 right-0 p-8 opacity-5 transform scale-125"><Icon size={120} /></div>
                                <div className="p-4 bg-indigo-50 text-indigo-600 rounded-full mb-4 z-10 shadow-sm relative"><Icon size={32} /></div>
                                <h3 className="font-bold text-gray-800 text-lg z-10 break-words w-full px-2 uppercase">{area}</h3>
                            </button>
                            {isManageMode && (
                                <div className="absolute top-3 right-3 flex gap-2 z-20">
                                    <button onClick={() => { setInputName(area); setShowRenameModal(area); }} className="p-2 bg-white text-indigo-600 rounded shadow border"><Edit2 size={16} /></button>
                                    <button onClick={() => setShowDeleteModal(area)} className="p-2 bg-white text-red-600 rounded shadow border"><Trash2 size={16} /></button>
                                </div>
                            )}
                        </div>
                     );
                 })}
            </div>
        ) : (
            /* VISTA DE CONTENIDO (CARPETAS + ARCHIVOS) */
            <div className="space-y-8 animate-in fade-in duration-300">

                {/* 1. GRID DE CARPETAS (SOLO EN RAÍZ Y SI NO ES BÚSQUEDA) */}
                {visibleFolders.length > 0 && !currentFolder && !isSearching && (
                    <div>
                        <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-4 flex items-center">
                            <FolderIcon size={14} className="mr-2" /> Carpetas
                        </h3>
                        <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-4">
                            {visibleFolders.map(folder => {
                                // Calculamos documentos dentro para el badge, respetando el TAB seleccionado
                                const count = getFolderCount(folder.id);
                                return (
                                    <button
                                        key={folder.id}
                                        onClick={() => setCurrentFolder(folder)}
                                        className="bg-white p-4 rounded-xl border border-gray-200 hover:border-indigo-400 hover:shadow-md transition-all text-left group flex flex-col justify-between h-32 relative overflow-hidden"
                                    >
                                        <div className="absolute top-0 right-0 p-2 opacity-5 group-hover:opacity-10 transition-opacity">
                                            <FolderIcon size={64} className="text-indigo-900" />
                                        </div>
                                        <div className="p-2 bg-indigo-50 text-indigo-600 rounded-lg w-fit group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                                            <FolderIcon size={20} fill="currentColor" fillOpacity={0.2} />
                                        </div>
                                        <div>
                                            <h4 className="font-bold text-gray-800 text-sm truncate uppercase group-hover:text-indigo-700">{folder.name}</h4>
                                            <p className="text-xs text-gray-400">{count} documentos</p>
                                        </div>
                                    </button>
                                );
                            })}
                        </div>
                    </div>
                )}

                {/* 2. LISTA DE ARCHIVOS */}
                <div>
                    {(visibleFolders.length > 0 && visibleDocs.length > 0) && (
                        <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-4 flex items-center mt-8">
                            <FileText size={14} className="mr-2" /> Archivos
                        </h3>
                    )}

                    {/* VISTA DE ARCHIVOS (Grid) */}
                    {visibleDocs.length > 0 && (
                        <div className="grid grid-cols-1 gap-3">
                            {visibleDocs.map(proc => {
                                const isExpired = viewTab === 'history';
                                return (
                                    <div key={proc.$id} className={`flex items-center justify-between p-4 bg-white rounded-lg border transition-all group ${isExpired ? 'border-gray-200 hover:bg-gray-50 opacity-75' : 'border-gray-100 hover:border-indigo-300 hover:shadow-md'}`}>
                                        <Link to={`/procedure/${proc.$id}`} className="flex items-center space-x-4 flex-1">
                                            <div className={`p-2.5 rounded-lg border shadow-sm ${isExpired ? 'bg-gray-100 text-gray-400' : 'bg-white text-indigo-600 border-indigo-50 group-hover:bg-indigo-600 group-hover:text-white transition-colors'}`}>
                                                <FileText size={20} />
                                            </div>
                                            <div>
                                                <h4 className={`font-bold text-sm ${isExpired ? 'text-gray-500 line-through' : 'text-gray-800 group-hover:text-indigo-800'}`}>{proc.name}</h4>
                                                <div className="flex items-center space-x-2 mt-1">
                                                    <span className="text-[10px] font-mono bg-gray-100 text-gray-500 px-1.5 rounded border border-gray-200">{proc.code}</span>
                                                    {!isExpired && <span className={`text-[10px] px-1.5 py-0.5 rounded font-bold uppercase ${proc.status === 'Vigente' ? 'bg-emerald-50 text-emerald-700' : 'bg-amber-50 text-amber-700'}`}>{proc.status}</span>}
                                                    {isExpired && <span className="text-[10px] px-1.5 py-0.5 rounded font-bold uppercase bg-red-50 text-red-700">OBSOLETO</span>}
                                                    <span className="text-[10px] text-gray-400">v{proc.version}</span>
                                                </div>
                                            </div>
                                        </Link>
                                        <div className="flex items-center gap-2">
                                            {proc.attachmentUrl && proc.attachmentUrl !== '#' && (
                                                <button onClick={() => setViewFile({ url: proc.attachmentUrl!, name: proc.name })} className="p-2 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors" title="Previsualizar">
                                                    <Eye size={18} />
                                                </button>
                                            )}
                                            <Link to={`/procedure/${proc.$id}`}><ChevronRight size={18} className="text-gray-300 group-hover:text-indigo-500" /></Link>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    )}

                    {/* EMPTY STATE - SOLO SI NO HAY CARPETAS NI DOCUMENTOS */}
                    {visibleDocs.length === 0 && visibleFolders.length === 0 && (
                        <div className="text-center py-12 bg-white rounded-xl border border-dashed border-gray-200">
                            <div className="bg-gray-50 p-4 rounded-full inline-block mb-3">
                                {viewTab === 'active' ? <FolderOpen className="text-gray-300" size={32} /> : <Archive className="text-gray-300" size={32} />}
                            </div>
                            <p className="text-gray-500 font-medium">Esta carpeta está vacía.</p>
                            <p className="text-xs text-gray-400 mt-1">No se encontraron elementos {viewTab === 'active' ? 'vigentes' : 'caducos'}.</p>
                        </div>
                    )}
                </div>
            </div>
        )}
      </div>

      {viewFile && <FileViewerModal fileUrl={viewFile.url} fileName={viewFile.name} onClose={() => setViewFile(null)} />}

      {/* ADMIN MODALS (SIMPLIFICADOS) */}
      {showAddModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
              <div className="bg-white p-6 rounded-xl shadow-xl w-full max-w-sm">
                  <h3 className="font-bold mb-4">Nueva Área</h3>
                  <input value={inputName} onChange={e => setInputName(e.target.value)} className="w-full border p-2 rounded mb-4 uppercase" autoFocus />
                  <div className="flex justify-end gap-2"><button onClick={() => setShowAddModal(false)} className="px-4 py-2">Cancelar</button><button onClick={handleCreateArea} className="px-4 py-2 bg-indigo-600 text-white rounded">Crear</button></div>
              </div>
          </div>
      )}
      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
              <div className="bg-white p-6 rounded-xl shadow-xl w-full max-w-sm border-t-4 border-red-500">
                  <h3 className="font-bold mb-2">¿Eliminar {showDeleteModal}?</h3>
                  <p className="text-sm text-gray-500 mb-4">Esta acción no se puede deshacer.</p>
                  <div className="flex justify-end gap-2"><button onClick={() => setShowDeleteModal(null)} className="px-4 py-2">Cancelar</button><button onClick={handleDeleteArea} className="px-4 py-2 bg-red-600 text-white rounded">Eliminar</button></div>
              </div>
          </div>
      )}
      {showRenameModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
              <div className="bg-white p-6 rounded-xl shadow-xl w-full max-w-sm">
                  <h3 className="font-bold mb-4">Renombrar Área</h3>
                  <input value={inputName} onChange={e => setInputName(e.target.value)} className="w-full border p-2 rounded mb-4 uppercase" />
                  <div className="flex justify-end gap-2"><button onClick={() => setShowRenameModal(null)} className="px-4 py-2">Cancelar</button><button onClick={handleRenameArea} className="px-4 py-2 bg-indigo-600 text-white rounded">Guardar</button></div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { appwriteService, normalizeString } from '../services/appwriteService';
import { Procedure, Folder, Area } from '../types';
import { Search, Folder as FolderIcon, ChevronRight, FileText, ArrowLeft, Grid, Layers, Archive, Box, Activity, ClipboardCheck, Truck, Monitor, Users, ShoppingBag, FolderOpen, Eye, Settings, Plus, Edit2, Trash2, X, Save, AlertTriangle, CheckCircle, Info, Warehouse, RotateCcw, Shield, Briefcase, Wrench, Clock, CornerUpLeft } from 'lucide-react';
import { Link } from 'react-router-dom';
import { FileViewerModal } from '../components/FileViewerModal';

// Mapeo de Iconos por Área
const AREA_ICONS: {[key: string]: any} = {
  "PROYECTOS Y MEJORA CONTINUA": Activity,
  "MENSAJERIA Y DISTRIBUCION": Truck,
  "MENSAJERÍA Y DISTRIBUCIÓN": Truck,
  "CALIDAD": ClipboardCheck,
  "ALMACEN C": Box,
  "ALMACEN F": Box,
  "CENTRO DE DISTRIBUCIÓN": Warehouse,
  "CENTRO DE DISTRIBUCION": Warehouse,
  "EMPAQUE RETAIL": ShoppingBag,
  "EMPAQUE TV": ShoppingBag,
  "DEVOLUCIONES": Archive,
  "INVENTARIOS": Layers,
  "RECIBO": ArrowLeft,
  "REACONDICIONADO": RefreshIcon,
  "MAQUILA": Layers,
  "TECNOLOGÍAS DE LA INFORMACIÓN": Monitor,
  "TECNOLOGIAS DE LA INFORMACION": Monitor,
  "RECURSOS HUMANOS": Users,
  "LOGÍSTICA INVERSA": RotateCcw,
  "LOGISTICA INVERSA": RotateCcw,
  "MANTENIMIENTO": Wrench,
  "SEGURIDAD": Shield,
  "SEGURIDAD PATRIMONIAL": Shield,
  "COMPRAS": Briefcase,
  "VENTAS": Briefcase,
  "DIRECCIÓN": Briefcase,
  "DIRECCION": Briefcase,
  "ADMINISTRACIÓN": Briefcase,
  "ADMINISTRACION": Briefcase
};

function RefreshIcon(props: any) { return <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" {...props}><path d="M21 12a9 9 0 0 0-9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"/><path d="M3 3v5h5"/><path d="M3 12a9 9 0 0 0 9 9 9.75 9.75 0 0 0 6.74-2.74L21 16"/><path d="M16 16h5v5"/></svg>; }

const Toast = ({ message, type, onClose }: { message: string, type: 'success' | 'error', onClose: () => void }) => (
    <div className={`fixed bottom-6 right-6 z-[100] px-4 py-3 rounded-lg shadow-lg flex items-center gap-3 animate-in slide-in-from-bottom duration-300 border ${type === 'success' ? 'bg-emerald-50 border-emerald-200 text-emerald-800' : 'bg-red-50 border-red-200 text-red-800'}`}>
        {type === 'success' ? <CheckCircle size={20} className="text-emerald-600" /> : <AlertTriangle size={20} className="text-red-600" />}
        <span className="font-medium text-sm">{message}</span>
        <button onClick={onClose} className="ml-2 hover:opacity-70"><X size={16} /></button>
    </div>
);

export const Catalog: React.FC = () => {
  const { user } = useAuth();

  // Estados de Navegación
  const [selectedArea, setSelectedArea] = useState<string | null>(null);
  const [currentFolder, setCurrentFolder] = useState<Folder | null>(null); // NAVEGACIÓN: Carpeta actual
  const [searchTerm, setSearchTerm] = useState('');

  // Estados de Filtro (Vigente vs Histórico)
  const [viewTab, setViewTab] = useState<'active' | 'history'>('active');

  // Datos
  const [areaProcedures, setAreaProcedures] = useState<Procedure[]>([]);
  const [areaFolders, setAreaFolders] = useState<Folder[]>([]);
  const [loading, setLoading] = useState(false);
  const [availableAreas, setAvailableAreas] = useState<string[]>([]);

  // Estados Admin
  const [isManageMode, setIsManageMode] = useState(false);
  const [showAddModal, setShowAddModal] = useState(false);
  const [showRenameModal, setShowRenameModal] = useState<string | null>(null);
  const [showDeleteModal, setShowDeleteModal] = useState<string | null>(null);
  const [inputName, setInputName] = useState('');
  const [processing, setProcessing] = useState(false);

  // UI
  const [toast, setToast] = useState<{msg: string, type: 'success'|'error'} | null>(null);
  const [viewFile, setViewFile] = useState<{url: string, name: string} | null>(null);

  const isAdmin = user?.role === 'admin';
  const isSingleAreaUser = !isAdmin && user?.allowedAreas.length === 1;

  const showToast = (msg: string, type: 'success' | 'error') => {
      setToast({ msg, type });
      setTimeout(() => setToast(null), 4000);
  };

  const refreshAreas = async () => {
      const dbAreas = await appwriteService.getAllAreas();
      setAvailableAreas(dbAreas);
  };

  useEffect(() => {
    refreshAreas();
  }, []);

  useEffect(() => {
      if (isSingleAreaUser && !selectedArea && user?.allowedAreas[0]) {
          setSelectedArea(user.allowedAreas[0]);
      }
  }, [isSingleAreaUser, selectedArea, user]);

  const displayAreas = availableAreas.filter(area => {
      if (isAdmin) return true;
      const normalizedArea = normalizeString(area);
      return user?.allowedAreas.some(allowed => normalizeString(allowed) === normalizedArea);
  });

  // Carga inicial (Búsqueda global)
  useEffect(() => {
    if (searchTerm.length > 2 && user) {
        setLoading(true);
        setCurrentFolder(null); // Reset folder on global search
        appwriteService.getProcedures(user, searchTerm).then(docs => {
            setAreaProcedures(docs);
            setLoading(false);
        });
    }
  }, [searchTerm, user]);

  // Cargar contenido de Área
  useEffect(() => {
      const loadAreaContent = async () => {
          if (user && selectedArea && !searchTerm) {
              setLoading(true);
              try {
                  const [folders, docs] = await Promise.all([
                      appwriteService.getFolders(selectedArea),
                      appwriteService.getProcedures(user, '', selectedArea)
                  ]);
                  setAreaFolders(folders);
                  setAreaProcedures(docs);
              } catch (e) {
                  console.error(e);
              } finally {
                  setLoading(false);
              }
          }
      };
      loadAreaContent();
  }, [selectedArea, user, searchTerm]);

  // Manejo del botón "Atrás" inteligente
  const handleBack = () => {
      setSearchTerm('');

      if (currentFolder) {
          // Si estamos dentro de una carpeta, subimos al nivel raíz del área
          setCurrentFolder(null);
      } else {
          // Si estamos en raíz del área, volvemos al selector de áreas (si aplica)
          if (!isSingleAreaUser) {
              setSelectedArea(null);
              setAreaProcedures([]);
              setAreaFolders([]);
          }
      }
  };

  // --- LOGICA DE RENDERIZADO DE CARPETAS Y ARCHIVOS ---

  // 1. Filtrar TODOS los documentos del área según el TAB seleccionado (Vigente vs Histórico)
  const filteredByStatus = areaProcedures.filter(proc => {
      // Normalización robusta del status
      const rawStatus = proc.status ? String(proc.status) : 'VIGENTE';
      const statusUpper = rawStatus.toUpperCase().trim();

      // Definición de expirado
      const isExpired = statusUpper === 'CADUCO' || statusUpper === 'OBSOLETO' || statusUpper === 'HISTORICO';

      if (viewTab === 'active') {
          // Si estamos en VIGENTES, ocultamos lo caduco
          return !isExpired;
      } else {
          // Si estamos en CADUCOS, mostramos SOLO lo caduco
          return isExpired;
      }
  });

  // 2. Separar lo que se muestra en la vista actual (Raíz vs Carpeta)
  let visibleFolders: Folder[] = [];
  let visibleDocs: Procedure[] = [];

  if (selectedArea && !searchTerm) {
      if (currentFolder) {
          // VISTA DENTRO DE CARPETA:
          // Solo documentos que tengan este folder_id y pasen el filtro de status
          visibleFolders = []; 
          visibleDocs = filteredByStatus.filter(p => p.folder_id === currentFolder.id);
      } else {
          // VISTA RAÍZ DEL ÁREA:
          // Documentos sueltos (huérfanos) que pasen el filtro
          const validFolderIds = areaFolders.map(f => f.id);
          visibleDocs = filteredByStatus.filter(p => !p.folder_id || !validFolderIds.includes(p.folder_id));

          // Carpetas del área: SOLO MOSTRAR SI TIENEN CONTENIDO QUE COINCIDA CON EL FILTRO
          visibleFolders = areaFolders.filter(folder => {
              // Contamos cuántos documentos de este folder sobreviven al filtro (Vigente/Caduco)
              const matchingDocsCount = filteredByStatus.filter(p => p.folder_id === folder.id).length;
              return matchingDocsCount > 0;
          });
      }
  } else if (searchTerm) {
      // EN BÚSQUEDA: Todo plano
      visibleDocs = areaProcedures; 
  }

  // Helper para contar elementos para el badge de la carpeta
  const getFolderCount = (folderId: string) => {
      return filteredByStatus.filter(p => p.folder_id === folderId).length;
  };

  const isSearching = searchTerm.length > 0;
  const showBackButton = isSearching || (selectedArea && (!isSingleAreaUser || currentFolder));

  const getAreaIcon = (areaName: string) => {
      const upperName = areaName.toUpperCase();
      return AREA_ICONS[upperName] || Box;
  };

  // --- ADMIN HANDLERS ---
  const handleCreateArea = async () => {
      if (!inputName.trim()) return;
      setProcessing(true);
      const success = await appwriteService.createArea(inputName.trim());
      if (success) { await refreshAreas(); showToast(`Área creada`, 'success'); setShowAddModal(false); setInputName(''); }
      setProcessing(false);
  };
  const handleRenameArea = async () => {
      if (!showRenameModal || !inputName.trim()) return;
      setProcessing(true);
      const success = await appwriteService.renameArea(showRenameModal, inputName.trim());
      if (success) { await refreshAreas(); showToast(`Área renombrada`, 'success'); setShowRenameModal(null); setInputName(''); }
      setProcessing(false);
  };
  const handleDeleteArea = async () => {
      if (!showDeleteModal) return;
      setProcessing(true);
      const success = await appwriteService.deleteArea(showDeleteModal);
      if (success) { await refreshAreas(); showToast(`Área eliminada`, 'success'); setShowDeleteModal(null); }
      setProcessing(false);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 min-h-[600px] flex flex-col relative">
      {toast && <Toast message={toast.msg} type={toast.type} onClose={() => setToast(null)} />}

      {/* HEADER & NAVIGATION */}
      <div className="p-6 border-b border-gray-100 flex flex-col gap-4 bg-gray-50/30">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
            <div className="flex items-center w-full md:w-auto">
                {showBackButton && (
                    <button 
                        onClick={handleBack}
                        className="mr-3 p-2 hover:bg-white rounded-full text-indigo-700 transition-colors shadow-sm border border-transparent hover:border-gray-200"
                        title="Atrás"
                    >
                        <ArrowLeft size={20} />
                    </button>
                )}

                <div>
                    {isSearching ? (
                        <h2 className="text-xl font-bold text-gray-800">Buscando: "{searchTerm}"</h2>
                    ) : selectedArea ? (
                        <div>
                             <p className="text-xs text-gray-400 uppercase font-bold tracking-wider mb-0.5 flex items-center">
                                 {selectedArea}
                                 {currentFolder && <ChevronRight size={12} className="mx-1" />}
                                 {currentFolder && <span className="text-indigo-600">{currentFolder.name}</span>}
                             </p>
                             <h2 className="text-xl font-bold text-gray-800 flex items-center uppercase">
                                 {currentFolder ? currentFolder.name : 'Directorio Principal'}
                             </h2>
                        </div>
                    ) : (
                        <div className="flex items-center text-gray-800 font-bold text-lg">
                            <Grid size={20} className="mr-2 text-indigo-600" />
                            Catálogo de Procesos
                        </div>
                    )}
                </div>
            </div>

            <div className="flex items-center gap-3 w-full md:w-auto">
                <div className="relative flex-1 md:w-64">
                    <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={20} />
                    <input 
                        type="text" 
                        placeholder="Buscar globalmente..." 
                        className="w-full pl-10 pr-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-100 focus:border-indigo-500 outline-none transition-all shadow-sm"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>

                {isAdmin && !selectedArea && !isSearching && (
                    <button 
                        onClick={() => setIsManageMode(!isManageMode)}
                        className={`p-2.5 rounded-lg border transition-all ${isManageMode ? 'bg-indigo-600 text-white' : 'bg-white text-gray-500'}`}
                    >
                        <Settings size={20} className={isManageMode ? 'animate-spin-slow' : ''} />
                    </button>
                )}
            </div>
        </div>
      </div>

      {/* BODY */}
      <div className="flex-1 p-6 bg-gray-50/10 flex flex-col">

        {/* TABS (SOLO SI NO BUSCAMOS) */}
        {selectedArea && !isSearching && !loading && (
            <div className="flex justify-between items-center mb-6">
                <div className="flex space-x-1 bg-gray-100/50 p-1 rounded-lg border border-gray-200">
                    <button onClick={() => setViewTab('active')} className={`px-4 py-2 text-sm font-bold rounded-md transition-all flex items-center ${viewTab === 'active' ? 'bg-white text-indigo-700 shadow-sm ring-1 ring-black/5' : 'text-gray-500 hover:text-gray-700 hover:bg-white/50'}`}>
                        <CheckCircle size={16} className="mr-2" /> VIGENTES
                    </button>
                    <button onClick={() => setViewTab('history')} className={`px-4 py-2 text-sm font-bold rounded-md transition-all flex items-center ${viewTab === 'history' ? 'bg-white text-gray-700 shadow-sm ring-1 ring-black/5' : 'text-gray-400 hover:text-gray-600 hover:bg-white/50'}`}>
                        <Clock size={16} className="mr-2" /> CADUCOS
                    </button>
                </div>

                {currentFolder && (
                    <button onClick={handleBack} className="text-sm font-bold text-indigo-600 hover:underline flex items-center">
                        <CornerUpLeft size={16} className="mr-1" /> Subir Nivel
                    </button>
                )}
            </div>
        )}

        {loading ? (
             <div className="p-12 text-center text-gray-400 flex flex-col items-center">
                 <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-600 mb-4"></div>
                 Sincronizando...
             </div>
        ) : !selectedArea && !isSearching ? (
            /* VISTA SELECCIÓN DE ÁREA (GRID) */
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                 {isManageMode && (
                     <button onClick={() => { setInputName(''); setShowAddModal(true); }} className="flex flex-col items-center justify-center p-8 bg-white rounded-2xl border-2 border-dashed border-indigo-300 hover:bg-indigo-50 transition-all min-h-[240px] text-indigo-600 font-bold">
                        <Plus size={32} className="mb-2" /> AGREGAR ÁREA
                     </button>
                 )}
                 {displayAreas.map(area => {
                     const Icon = getAreaIcon(area);
                     return (
                        <div key={area} className="relative group-card">
                            <button
                                onClick={() => !isManageMode && setSelectedArea(area)}
                                className={`w-full h-full flex flex-col items-center justify-center p-8 bg-white rounded-2xl border transition-all relative overflow-hidden text-center min-h-[240px] ${isManageMode ? 'border-gray-200 opacity-90' : 'border-gray-200 hover:border-indigo-500 hover:shadow-xl hover:-translate-y-1'}`}
                                disabled={isManageMode}
                            >
                                <div className="absolute top-0 right-0 p-8 opacity-5 transform scale-125"><Icon size={120} /></div>
                                <div className="p-4 bg-indigo-50 text-indigo-600 rounded-full mb-4 z-10 shadow-sm relative"><Icon size={32} /></div>
                                <h3 className="font-bold text-gray-800 text-lg z-10 break-words w-full px-2 uppercase">{area}</h3>
                            </button>
                            {isManageMode && (
                                <div className="absolute top-3 right-3 flex gap-2 z-20">
                                    <button onClick={() => { setInputName(area); setShowRenameModal(area); }} className="p-2 bg-white text-indigo-600 rounded shadow border"><Edit2 size={16} /></button>
                                    <button onClick={() => setShowDeleteModal(area)} className="p-2 bg-white text-red-600 rounded shadow border"><Trash2 size={16} /></button>
                                </div>
                            )}
                        </div>
                     );
                 })}
            </div>
        ) : (
            /* VISTA DE CONTENIDO (CARPETAS + ARCHIVOS) */
            <div className="space-y-8 animate-in fade-in duration-300">

                {/* 1. GRID DE CARPETAS (SOLO EN RAÍZ Y SI NO ES BÚSQUEDA) */}
                {visibleFolders.length > 0 && !currentFolder && !isSearching && (
                    <div>
                        <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-4 flex items-center">
                            <FolderIcon size={14} className="mr-2" /> Carpetas
                        </h3>
                        <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-4">
                            {visibleFolders.map(folder => {
                                // Calculamos documentos dentro para el badge, respetando el TAB seleccionado
                                const count = getFolderCount(folder.id);
                                return (
                                    <button
                                        key={folder.id}
                                        onClick={() => setCurrentFolder(folder)}
                                        className="bg-white p-4 rounded-xl border border-gray-200 hover:border-indigo-400 hover:shadow-md transition-all text-left group flex flex-col justify-between h-32 relative overflow-hidden"
                                    >
                                        <div className="absolute top-0 right-0 p-2 opacity-5 group-hover:opacity-10 transition-opacity">
                                            <FolderIcon size={64} className="text-indigo-900" />
                                        </div>
                                        <div className="p-2 bg-indigo-50 text-indigo-600 rounded-lg w-fit group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                                            <FolderIcon size={20} fill="currentColor" fillOpacity={0.2} />
                                        </div>
                                        <div>
                                            <h4 className="font-bold text-gray-800 text-sm truncate uppercase group-hover:text-indigo-700">{folder.name}</h4>
                                            <p className="text-xs text-gray-400">{count} documentos</p>
                                        </div>
                                    </button>
                                );
                            })}
                        </div>
                    </div>
                )}

                {/* 2. LISTA DE ARCHIVOS */}
                <div>
                    {(visibleFolders.length > 0 && visibleDocs.length > 0) && (
                        <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-4 flex items-center mt-8">
                            <FileText size={14} className="mr-2" /> Archivos
                        </h3>
                    )}

                    {/* VISTA DE ARCHIVOS (Grid) */}
                    {visibleDocs.length > 0 && (
                        <div className="grid grid-cols-1 gap-3">
                            {visibleDocs.map(proc => {
                                const isExpired = viewTab === 'history';
                                return (
                                    <div key={proc.$id} className={`flex items-center justify-between p-4 bg-white rounded-lg border transition-all group ${isExpired ? 'border-gray-200 hover:bg-gray-50 opacity-75' : 'border-gray-100 hover:border-indigo-300 hover:shadow-md'}`}>
                                        <Link to={`/procedure/${proc.$id}`} className="flex items-center space-x-4 flex-1">
                                            <div className={`p-2.5 rounded-lg border shadow-sm ${isExpired ? 'bg-gray-100 text-gray-400' : 'bg-white text-indigo-600 border-indigo-50 group-hover:bg-indigo-600 group-hover:text-white transition-colors'}`}>
                                                <FileText size={20} />
                                            </div>
                                            <div>
                                                <h4 className={`font-bold text-sm ${isExpired ? 'text-gray-500 line-through' : 'text-gray-800 group-hover:text-indigo-800'}`}>{proc.name}</h4>
                                                <div className="flex items-center space-x-2 mt-1">
                                                    <span className="text-[10px] font-mono bg-gray-100 text-gray-500 px-1.5 rounded border border-gray-200">{proc.code}</span>
                                                    {!isExpired && <span className={`text-[10px] px-1.5 py-0.5 rounded font-bold uppercase ${proc.status === 'Vigente' ? 'bg-emerald-50 text-emerald-700' : 'bg-amber-50 text-amber-700'}`}>{proc.status}</span>}
                                                    {isExpired && <span className="text-[10px] px-1.5 py-0.5 rounded font-bold uppercase bg-red-50 text-red-700">OBSOLETO</span>}
                                                    <span className="text-[10px] text-gray-400">v{proc.version}</span>
                                                </div>
                                            </div>
                                        </Link>
                                        <div className="flex items-center gap-2">
                                            {proc.attachmentUrl && proc.attachmentUrl !== '#' && (
                                                <button onClick={() => setViewFile({ url: proc.attachmentUrl!, name: proc.name })} className="p-2 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors" title="Previsualizar">
                                                    <Eye size={18} />
                                                </button>
                                            )}
                                            <Link to={`/procedure/${proc.$id}`}><ChevronRight size={18} className="text-gray-300 group-hover:text-indigo-500" /></Link>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    )}

                    {/* EMPTY STATE - SOLO SI NO HAY CARPETAS NI DOCUMENTOS */}
                    {visibleDocs.length === 0 && visibleFolders.length === 0 && (
                        <div className="text-center py-12 bg-white rounded-xl border border-dashed border-gray-200">
                            <div className="bg-gray-50 p-4 rounded-full inline-block mb-3">
                                {viewTab === 'active' ? <FolderOpen className="text-gray-300" size={32} /> : <Archive className="text-gray-300" size={32} />}
                            </div>
                            <p className="text-gray-500 font-medium">Esta carpeta está vacía.</p>
                            <p className="text-xs text-gray-400 mt-1">No se encontraron elementos {viewTab === 'active' ? 'vigentes' : 'caducos'}.</p>
                        </div>
                    )}
                </div>
            </div>
        )}
      </div>

      {viewFile && <FileViewerModal fileUrl={viewFile.url} fileName={viewFile.name} onClose={() => setViewFile(null)} />}

      {/* ADMIN MODALS (SIMPLIFICADOS) */}
      {showAddModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
              <div className="bg-white p-6 rounded-xl shadow-xl w-full max-w-sm">
                  <h3 className="font-bold mb-4">Nueva Área</h3>
                  <input value={inputName} onChange={e => setInputName(e.target.value)} className="w-full border p-2 rounded mb-4 uppercase" autoFocus />
                  <div className="flex justify-end gap-2"><button onClick={() => setShowAddModal(false)} className="px-4 py-2">Cancelar</button><button onClick={handleCreateArea} className="px-4 py-2 bg-indigo-600 text-white rounded">Crear</button></div>
              </div>
          </div>
      )}
      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
              <div className="bg-white p-6 rounded-xl shadow-xl w-full max-w-sm border-t-4 border-red-500">
                  <h3 className="font-bold mb-2">¿Eliminar {showDeleteModal}?</h3>
                  <p className="text-sm text-gray-500 mb-4">Esta acción no se puede deshacer.</p>
                  <div className="flex justify-end gap-2"><button onClick={() => setShowDeleteModal(null)} className="px-4 py-2">Cancelar</button><button onClick={handleDeleteArea} className="px-4 py-2 bg-red-600 text-white rounded">Eliminar</button></div>
              </div>
          </div>
      )}
      {showRenameModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
              <div className="bg-white p-6 rounded-xl shadow-xl w-full max-w-sm">
                  <h3 className="font-bold mb-4">Renombrar Área</h3>
                  <input value={inputName} onChange={e => setInputName(e.target.value)} className="w-full border p-2 rounded mb-4 uppercase" />
                  <div className="flex justify-end gap-2"><button onClick={() => setShowRenameModal(null)} className="px-4 py-2">Cancelar</button><button onClick={handleRenameArea} className="px-4 py-2 bg-indigo-600 text-white rounded">Guardar</button></div>
              </div>
          </div>
      )}
    </div>
  );
};

payload.text:
Es un error común cuando se intenta forzar la descarga de archivos desde dominios externos (como Supabase) manipulando el nombre del archivo en el Frontend.

Aquí tienes el análisis detallado y la solución técnica.

### 🔍 Diagnóstico del Problema

El código actual en `handleDownloadClick` intenta hacer lo siguiente:
1.  Hace una petición `fetch` a la URL del archivo.
2.  Convierte la respuesta en un `Blob` (un objeto de archivo en memoria).
3.  Crea un enlace falso para descargar ese Blob con el nombre limpio (sin UUID).

**¿Por qué descarga un "token" o archivo corrupto?**
El problema es que `fetch` no rechaza la promesa automáticamente si el servidor responde con un error (ej. 400 Bad Request, 403 Forbidden, o 404 Not Found).
1.  Si Supabase responde, por ejemplo, con un error JSON diciendo `{"error": "expired_token"}` o `{"message": "Not found"}`, el código actual **toma ese texto JSON, lo convierte en Blob y te lo descarga como si fuera un PDF.**
2.  Cuando abres el archivo, ves texto plano (que parece un token) en lugar del documento real.
3.  Además, el nombre del archivo se está extrayendo de la URL completa, lo cual a veces incluye parámetros de consulta (`?token=...`) si Supabase firma las URLs, haciendo que el nombre del archivo sea larguísimo y extraño.

### 🛠️ La Solución Propuesta

Debemos blindar la función `handleDownloadClick` en `pages/ProcedureDetail.tsx`.

**La lógica corregida debe hacer esto:**
1.  **Limpiar la URL antes de procesarla:** Quitar cualquier query param (`?token=...`) para obtener el nombre real de la extensión.
2.  **Verificar `response.ok`:** Antes de crear el Blob, preguntar si la respuesta fue exitosa (status 200). Si no, lanzar un error para ir al método de respaldo.
3.  **Fallback Robusto:** Si el método elegante (cambiar nombre) falla por CORS o errores de red, usar `window.open` para que el navegador maneje la descarga nativamente (aunque el nombre salga con el UUID, el archivo será válido).

### 📝 Código Corregido (Para cuando me autorices aplicarlo)

Esta es la lógica que implementaré en `pages/ProcedureDetail.tsx` cuando me des luz verde:

```typescript
  const handleDownloadClick = async () => {
    if (!downloadReq || !proc?.attachmentUrl) return;

    try {
      // 1. Limpieza de URL para obtener nombre base (quitando query params como ?token=...)
      // Esto evita que el nombre del archivo incluya el token de seguridad
      const cleanUrl = proc.attachmentUrl.split('?')[0]; 
      const urlParts = cleanUrl.split('/');
      let fileName = decodeURIComponent(urlParts[urlParts.length - 1]);

      // 2. Limpiar el UUID del nombre (Patrón: 8-4-4-4-12 caracteres + guion)
      const uuidRegex = /^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}-/;
      fileName = fileName.replace(uuidRegex, '');

      // 3. Petición del archivo
      const response = await fetch(proc.attachmentUrl);

      // CRITICO: Verificar si la respuesta es válida (Status 200-299)
      // Si Supabase devuelve un error (JSON), lanzamos error para no descargar basura.
      if (!response.ok) throw new Error(`Error red: ${response.status}`);

      const blob = await response.blob();

      // 4. Crear enlace de descarga forzada con nombre limpio
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.style.display = 'none';
      a.href = url;
      a.download = fileName; 
      document.body.appendChild(a);
      a.click();

      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);

    } catch (error) {
      console.error("Falló descarga con nombre limpio, usando método directo:", error);
      // Fallback: Descarga directa del navegador. 
      // El nombre puede salir con UUID, pero aseguramos que el archivo abre.
      window.open(proc.attachmentUrl, '_blank', 'noopener,noreferrer');
    }

    // 5. Quemar el token
    await appwriteService.consumeDownloadToken(downloadReq.id);
    setDownloadReq(null); 
  };
```

**¿Deseas que proceda a aplicar esta corrección al archivo `pages/ProcedureDetail.tsx`?**

