import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { appwriteService } from '../services/appwriteService';
import { Procedure, DownloadRequest } from '../types';
import { 
  ArrowLeft, Video, Info, Calendar, User, History, 
  ExternalLink, FileText, Loader, Eye, Key, Clock, CheckCircle, Lock, XCircle
} from 'lucide-react';
import { FileViewerModal } from '../components/FileViewerModal';
import { useAuth } from '../context/AuthContext';

export const ProcedureDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const { user } = useAuth();
  const [proc, setProc] = useState<Procedure | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'video'>('info');
  const [loading, setLoading] = useState(true);
  const [viewFile, setViewFile] = useState<{url: string, name: string} | null>(null);

  // Estado para la solicitud de descarga
  const [downloadReq, setDownloadReq] = useState<DownloadRequest | null>(null);
  const [requesting, setRequesting] = useState(false);

  useEffect(() => {
    if (id && user) {
      setLoading(true);
      Promise.all([
        appwriteService.getProcedureById(id),
        appwriteService.getDownloadStatus(user.$id, id)
      ]).then(([data, status]) => {
        setProc(data || null);
        setDownloadReq(status);
        setLoading(false);
      });
    }
  }, [id, user]);

  const handleRequestDownload = async () => {
    if (!proc || !user) return;
    setRequesting(true);
    const success = await appwriteService.requestDownload(user.$id, proc.$id, proc.name);
    if (success) {
      // Refrescar estado
      const status = await appwriteService.getDownloadStatus(user.$id, proc.$id);
      setDownloadReq(status);
    } else {
      alert("No se pudo procesar la solicitud. Intente más tarde.");
    }
    setRequesting(false);
  };

  const handleDownloadClick = async () => {
    if (!downloadReq || !proc?.attachmentUrl) return;

    try {
      // 1. Limpieza de URL para obtener nombre base (quitando query params como ?token=...)
      // Esto evita que el nombre del archivo incluya el token de seguridad
      const cleanUrl = proc.attachmentUrl.split('?')[0]; 
      const urlParts = cleanUrl.split('/');
      let fileName = decodeURIComponent(urlParts[urlParts.length - 1]);

      // 2. Limpiar el UUID del nombre (Patrón: 8-4-4-4-12 caracteres + guion)
      const uuidRegex = /^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}-/;
      fileName = fileName.replace(uuidRegex, '');

      // 3. Petición del archivo
      const response = await fetch(proc.attachmentUrl);

      // CRITICO: Verificar si la respuesta es válida (Status 200-299)
      // Si Supabase devuelve un error (JSON), lanzamos error para no descargar basura.
      if (!response.ok) throw new Error(`Error red: ${response.status}`);

      const blob = await response.blob();

      // 4. Crear enlace de descarga forzada con nombre limpio
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.style.display = 'none';
      a.href = url;
      a.download = fileName; 
      document.body.appendChild(a);
      a.click();

      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);

    } catch (error) {
      console.error("Falló descarga con nombre limpio, usando método directo:", error);
      // Fallback: Descarga directa del navegador. 
      // El nombre puede salir con UUID, pero aseguramos que el archivo abre.
      window.open(proc.attachmentUrl, '_blank', 'noopener,noreferrer');
    }

    // 5. Quemar el token
    await appwriteService.consumeDownloadToken(downloadReq.id);
    setDownloadReq(null); 
  };

  const renderDownloadButton = () => {
    if (!downloadReq) {
      // Estado Inicial: Solicitar
      return (
        <button 
          onClick={handleRequestDownload}
          disabled={requesting}
          className="flex items-center px-4 py-2 bg-gray-800 hover:bg-gray-900 text-white rounded-lg font-bold text-sm transition-colors shadow-sm disabled:opacity-50"
          title="Solicitar permiso para descargar original"
        >
          {requesting ? <Loader size={16} className="animate-spin mr-2" /> : <Key size={16} className="mr-2 text-yellow-400" />}
          Solicitar Original
        </button>
      );
    }

    if (downloadReq.status === 'pending') {
      return (
        <button 
          disabled
          className="flex items-center px-4 py-2 bg-amber-100 text-amber-800 border border-amber-200 rounded-lg font-bold text-sm cursor-not-allowed"
          title="Esperando autorización de un administrador"
        >
          <Clock size={16} className="mr-2" />
          En Revisión...
        </button>
      );
    }

    if (downloadReq.status === 'approved') {
      return (
        <button 
          onClick={handleDownloadClick}
          className="flex items-center px-4 py-2 bg-emerald-600 hover:bg-emerald-700 text-white rounded-lg font-bold text-sm transition-all shadow-md animate-pulse"
          title="Autorizado: Clic para descargar (1 solo uso)"
        >
          <CheckCircle size={16} className="mr-2" />
          Descargar (1 uso)
        </button>
      );
    }

    if (downloadReq.status === 'rejected') {
       return (
        <div className="flex items-center space-x-2">
           <span className="text-xs text-red-600 font-bold flex items-center px-2 py-1 bg-red-50 rounded border border-red-100">
              <XCircle size={12} className="mr-1"/> Denegado
           </span>
           <button 
             onClick={handleRequestDownload} 
             disabled={requesting}
             className="text-xs text-indigo-600 underline hover:text-indigo-800"
           >
             Reintentar
           </button>
        </div>
       );
    }

    return null;
  };

  if (loading) return <div className="min-h-screen flex items-center justify-center bg-gray-50"><Loader className="animate-spin text-indigo-600 mr-2" /> Cargando procedimiento...</div>;
  if (!proc) return <div className="p-8 text-center">Procedimiento no encontrado o sin acceso.</div>;

  return (
    <div className="space-y-6">
      <Link to="/catalog" className="inline-flex items-center text-gray-500 hover:text-indigo-700 transition-colors font-medium">
        <ArrowLeft size={16} className="mr-2" />
        Volver al Catálogo
      </Link>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        {/* Header */}
        <div className="p-6 md:p-8 border-b border-gray-100 bg-gray-50/30">
          <div className="flex flex-col md:flex-row justify-between md:items-start gap-4">
            <div>
              <div className="flex items-center space-x-3 mb-2">
                <span className="font-mono text-xs font-bold text-indigo-700 bg-indigo-50 px-2 py-1 rounded border border-indigo-100">{proc.code}</span>
                <span className="text-xs text-gray-500 font-semibold uppercase tracking-wide">Versión {proc.version}</span>
              </div>
              <h1 className="text-2xl md:text-3xl font-bold text-gray-900">{proc.name}</h1>
              <p className="text-sm font-bold text-indigo-800 mt-2 uppercase flex items-center">
                  <span className="w-2 h-2 rounded-full bg-indigo-500 mr-2"></span>
                  {proc.area}
              </p>
            </div>

            <div className="flex flex-col items-end gap-2">
                <div className={`px-4 py-1.5 rounded-full text-sm font-bold border ${proc.status === 'Vigente' ? 'bg-indigo-100 border-indigo-200 text-indigo-800' : 'bg-amber-50 border-amber-200 text-amber-700'}`}>
                  {proc.status}
                </div>

                {proc.attachmentUrl && proc.attachmentUrl !== '#' && (
                  <div className="flex space-x-2 mt-2 items-center">
                     <button
                        onClick={() => setViewFile({ url: proc.attachmentUrl!, name: proc.name })}
                        className="flex items-center px-4 py-2 bg-indigo-100 hover:bg-indigo-200 text-indigo-800 rounded-lg font-bold text-sm transition-colors shadow-sm"
                     >
                        <Eye size={16} className="mr-2" />
                        Previsualizar
                     </button>

                     {/* Lógica de Descarga Restringida */}
                     {renderDownloadButton()}
                  </div>
                )}
            </div>
          </div>

          <div className="flex flex-wrap gap-6 mt-6 text-sm text-gray-500">
            <div className="flex items-center">
              <Calendar size={16} className="mr-2 text-indigo-400" />
              Actualizado: {new Date(proc.updatedAt).toLocaleDateString()}
            </div>
            <div className="flex items-center">
              <User size={16} className="mr-2 text-indigo-400" />
              Responsable: {proc.responsible}
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div className="flex border-b border-gray-100 bg-white sticky top-0 z-10 overflow-x-auto">
          <button 
            onClick={() => setActiveTab('info')}
            className={`flex items-center px-6 py-4 font-bold text-sm transition-colors border-b-2 whitespace-nowrap ${activeTab === 'info' ? 'border-indigo-700 text-indigo-800 bg-indigo-50/30' : 'border-transparent text-gray-500 hover:text-gray-800 hover:bg-gray-50'}`}
          >
            <Info size={18} className="mr-2" />
            Detalles Generales
          </button>

          {proc.urlVideo && (
            <button 
              onClick={() => setActiveTab('video')}
              className={`flex items-center px-6 py-4 font-bold text-sm transition-colors border-b-2 whitespace-nowrap ${activeTab === 'video' ? 'border-indigo-700 text-indigo-800 bg-indigo-50/30' : 'border-transparent text-gray-500 hover:text-gray-800 hover:bg-gray-50'}`}
            >
              <Video size={18} className="mr-2" />
              Video Tutorial
            </button>
          )}
        </div>

        {/* Content */}
        <div className="p-6 md:p-8 min-h-[400px]">
          {activeTab === 'info' && (
            <div className="max-w-4xl animate-in fade-in duration-300">
              <div 
                className="prose prose-indigo prose-sm md:prose-base text-gray-600"
                dangerouslySetInnerHTML={{ __html: proc.description }}
              />

              <div className="mt-12 pt-8 border-t border-gray-100">
                <h3 className="flex items-center font-bold text-gray-800 mb-4">
                  <History size={18} className="mr-2 text-indigo-600" /> Historial de Cambios
                </h3>
                {proc.history.length > 0 ? (
                  <ul className="space-y-4">
                    {proc.history.map((h, i) => (
                      <li key={i} className="flex gap-4 text-sm group">
                        <div className="font-mono text-indigo-400 font-bold w-16 group-hover:text-indigo-600">v{h.version}</div>
                        <div className="flex-1">
                          <p className="font-medium text-gray-800">{h.changeLog}</p>
                          <p className="text-gray-400 text-xs mt-0.5">{h.date} - por {h.author}</p>
                        </div>
                      </li>
                    ))}
                  </ul>
                ) : (
                  <p className="text-gray-400 italic text-sm">No hay historial previo registrado.</p>
                )}
              </div>
            </div>
          )}

          {activeTab === 'video' && proc.urlVideo && (
            <div className="aspect-video w-full max-w-4xl mx-auto bg-black rounded-lg overflow-hidden shadow-2xl border-4 border-gray-900 animate-in fade-in duration-300">
              <iframe 
                src={proc.urlVideo} 
                className="w-full h-full" 
                title="Video Tutorial"
                allowFullScreen
              />
            </div>
          )}
        </div>
      </div>

      {viewFile && (
        <FileViewerModal 
            fileUrl={viewFile.url} 
            fileName={viewFile.name} 
            onClose={() => setViewFile(null)} 
        />
      )}
    </div>
  );
};

async adminGetDownloadRequests(): Promise<DownloadRequest[]> {
  if (isLegacyReady() && supabase) {
     // La consulta incluye 'users' para obtener nombre y correo del solicitante
     const { data, error } = await supabase
       .from('download_requests')
       .select(`*, users (name, email, area)`)
       .in('status', ['pending', 'approved', 'consumed']) // AHORA INCLUIMOS APROBADOS Y CONSUMIDOS
       .order('requested_at', { ascending: false }); // Ordenamos por más reciente

     if (error) {
         console.error("Error fetching download requests (check FK relations):", error);
         return [];
     }

     return data.map((r: any) => ({
       id: r.id,
       user_id: r.user_id,
       procedure_id: r.procedure_id,
       procedure_name: r.procedure_name,
       status: r.status,
       requested_at: r.requested_at,
       user_name: r.users?.name || 'Usuario',
       user_email: r.users?.email || 'N/A',
       user_area: (r.users?.area || 'N/A').toUpperCase()
     }));
  }
  return [];
},

async adminRespondToDownloadRequest(requestId: string, status: 'approved' | 'rejected'): Promise<boolean> {
  if (isLegacyReady() && supabase) {
    const { error } = await supabase
      .from('download_requests')
      .update({ status, responded_at: new Date().toISOString() })
      .eq('id', requestId);
    return !error;
  }
  return false;
},

import React, { useEffect, useState } from 'react';
import { appwriteService } from '../services/appwriteService';
import { DownloadRequest } from '../types';
import { Key, RefreshCw, CheckCircle, Download, FileText, CheckCheck, Clock, AlertCircle } from 'lucide-react';

export const AdminRequests: React.FC = () => {
  const [downloadRequests, setDownloadRequests] = useState<DownloadRequest[]>([]);
  const [loading, setLoading] = useState(true);

  const loadData = async () => {
    setLoading(true);
    const dls = await appwriteService.adminGetDownloadRequests();
    setDownloadRequests(dls);
    setLoading(false);
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleDownloadResponse = async (id: string, status: 'approved' | 'rejected') => {
      const success = await appwriteService.adminRespondToDownloadRequest(id, status);
      if (success) {
          // Actualizamos el estado localmente para reflejar el cambio inmediato
          setDownloadRequests(prev => prev.map(r => 
              r.id === id ? { ...r, status: status } : r
          ));
      }
  };

  return (
    <div className="space-y-6">
       <div className="bg-white p-6 rounded-xl shadow-sm border border-indigo-100 flex items-center justify-between">
            <div className="flex items-center space-x-3">
                <div className="p-3 bg-indigo-50 rounded-lg">
                    <Key size={24} className="text-indigo-700" />
                </div>
                <div>
                    <h3 className="text-xl font-bold text-gray-900">Solicitudes de Acceso a Archivos</h3>
                    <p className="text-sm text-gray-500">Autoriza, deniega y monitorea el estado de descargas de documentos protegidos.</p>
                </div>
            </div>
            <button 
                onClick={loadData} 
                className="p-2 text-gray-500 hover:bg-gray-50 rounded-lg transition-colors"
                title="Actualizar lista"
            >
                <RefreshCw size={20} className={loading ? 'animate-spin' : ''} />
            </button>
       </div>

       {loading ? (
           <div className="text-center py-20 text-gray-400">Cargando solicitudes...</div>
       ) : downloadRequests.length === 0 ? (
           <div className="text-center py-20 bg-white rounded-xl border border-gray-100 shadow-sm">
               <CheckCircle size={64} className="mx-auto text-emerald-100 mb-4" />
               <p className="text-lg font-bold text-gray-700">¡Todo al día!</p>
               <p className="text-gray-400">No hay historial de solicitudes recientes.</p>
           </div>
       ) : (
           <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {downloadRequests.map(req => {
                  const isPending = req.status === 'pending';
                  const isConsumed = req.status === 'consumed';
                  const isApproved = req.status === 'approved';

                  return (
                    <div key={req.id} className={`bg-white p-6 rounded-xl shadow-md border relative overflow-hidden group transition-colors ${isPending ? 'border-amber-200' : isConsumed ? 'border-gray-200 opacity-80' : 'border-emerald-200'}`}>
                        {/* Status Icon Background */}
                        <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
                            {isConsumed ? <CheckCheck size={80} /> : <Download size={80} />}
                        </div>

                        <div className="relative z-10">
                            <div className="flex items-center justify-between mb-4">
                                <div className="flex items-center space-x-2">
                                    <span className="bg-indigo-100 text-indigo-800 text-xs font-bold px-2.5 py-1 rounded border border-indigo-200">
                                        {req.user_area}
                                    </span>
                                    {/* STATUS BADGE */}
                                    {isPending && (
                                        <span className="bg-amber-100 text-amber-800 text-xs font-bold px-2 py-1 rounded border border-amber-200 flex items-center">
                                            <Clock size={12} className="mr-1" /> Pendiente
                                        </span>
                                    )}
                                    {isApproved && (
                                        <span className="bg-emerald-50 text-emerald-700 text-xs font-bold px-2 py-1 rounded border border-emerald-100 flex items-center">
                                            <AlertCircle size={12} className="mr-1" /> Esperando Descarga
                                        </span>
                                    )}
                                    {isConsumed && (
                                        <span className="bg-gray-100 text-gray-600 text-xs font-bold px-2 py-1 rounded border border-gray-200 flex items-center">
                                            <CheckCheck size={12} className="mr-1" /> Ya Descargado
                                        </span>
                                    )}
                                </div>
                                <span className="text-xs font-mono text-gray-400 bg-gray-50 px-2 py-1 rounded">
                                    {new Date(req.requested_at).toLocaleDateString()}
                                </span>
                            </div>

                            <div className="mb-4">
                                <h4 className="font-bold text-lg text-gray-900 leading-tight">{req.user_name}</h4>
                                <p className="text-sm text-gray-500">{req.user_email}</p>
                            </div>

                            <div className="bg-gray-50 p-4 rounded-lg border border-gray-100 mb-6 flex items-start">
                                <FileText size={20} className="text-indigo-500 mr-3 mt-0.5" />
                                <div>
                                    <p className="text-xs font-bold text-gray-500 uppercase tracking-wide mb-1">Solicita archivo:</p>
                                    <p className="text-sm font-bold text-indigo-900 leading-snug">
                                        {req.procedure_name}
                                    </p>
                                </div>
                            </div>

                            {/* ACTION BUTTONS (Solo si es Pendiente) */}
                            {isPending ? (
                                <div className="flex gap-4">
                                    <button 
                                        onClick={() => handleDownloadResponse(req.id, 'rejected')}
                                        className="flex-1 py-3 border border-red-200 text-red-600 font-bold text-sm rounded-lg hover:bg-red-50 transition-colors"
                                    >
                                        Denegar
                                    </button>
                                    <button 
                                        onClick={() => handleDownloadResponse(req.id, 'approved')}
                                        className="flex-1 py-3 bg-emerald-600 text-white font-bold text-sm rounded-lg hover:bg-emerald-700 shadow-sm transition-colors flex items-center justify-center"
                                    >
                                        <CheckCircle size={16} className="mr-2" />
                                        Autorizar
                                    </button>
                                </div>
                            ) : (
                                // INFO MESSAGES FOR PROCESSED REQUESTS
                                <div className={`text-center py-2 text-sm font-bold rounded-lg border ${
                                    isConsumed ? 'bg-gray-50 text-gray-500 border-gray-200' : 
                                    isApproved ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 'bg-red-50 text-red-500 border-red-100'
                                }`}>
                                    {isConsumed ? "El usuario ya descargó este archivo." : 
                                     isApproved ? "Autorizado. Usuario aún no descarga." : "Solicitud Denegada."}
                                </div>
                            )}
                        </div>
                    </div>
                  );
              })}
           </div>
       )}
    </div>
  );
};

import { createClient } from '@supabase/supabase-js';
import { User, Procedure, Folder, Stats, ConsultationMessage, DownloadRequest, OnlineUser, Area } from '../types';

// Initialize Supabase client
const supabaseUrl = process.env.REACT_APP_SUPABASE_URL || '';
const supabaseKey = process.env.REACT_APP_SUPABASE_ANON_KEY || '';

const supabase = (supabaseUrl && supabaseKey) ? createClient(supabaseUrl, supabaseKey) : null;

const isLegacyReady = () => !!supabase;

export const normalizeString = (str: string) => {
  return str ? str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase() : "";
};

export const appwriteService = {
  // Auth & User Session
  async getCurrentUser(): Promise<User | null> {
    if (!supabase) return null;
    const { data: { session } } = await supabase.auth.getSession();
    if (!session) return null;

    const { data, error } = await supabase.from('users').select('*').eq('id', session.user.id).single();
    if (error || !data) return null;

    return {
        $id: data.id,
        name: data.name,
        email: data.email,
        area: data.area,
        allowedAreas: data.allowed_areas || [],
        role: data.role,
        avatarUrl: data.avatar_url,
        privacyAccepted: data.privacy_accepted,
        signedName: data.signed_name,
        signedDepartment: data.signed_department,
        lastIp: data.last_ip,
        isImpersonating: false
    };
  },

  async login(email: string, password?: string): Promise<User | null> {
    if (!supabase) throw new Error("Database connection not configured");
    if (!password) throw new Error("Password is required");

    const { error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) throw error;
    return this.getCurrentUser();
  },

  async logout(): Promise<void> {
    if (supabase) await supabase.auth.signOut();
  },

  async updateUserPrivacy(userId: string, signedName?: string, signedDepartment?: string): Promise<boolean> {
    if (!supabase) return false;
    const { error } = await supabase.from('users').update({
        privacy_accepted: true,
        signed_name: signedName,
        signed_department: signedDepartment,
        privacy_accepted_at: new Date().toISOString()
    }).eq('id', userId);
    return !error;
  },

  async uploadUserAvatar(userId: string, file: File): Promise<string | null> {
    if (!supabase) return null;
    const fileExt = file.name.split('.').pop();
    const fileName = `${userId}-${Date.now()}.${fileExt}`;
    const filePath = `avatars/${fileName}`;

    const { error: uploadError } = await supabase.storage.from('avatars').upload(filePath, file);
    if (uploadError) return null;

    const { data } = supabase.storage.from('avatars').getPublicUrl(filePath);
    if (data) {
        await supabase.from('users').update({ avatar_url: data.publicUrl }).eq('id', userId);
        return data.publicUrl;
    }
    return null;
  },

  async deleteUserPrivacySignature(userId: string): Promise<boolean> {
    if (!supabase) return false;
    const { error } = await supabase.from('users').update({
        privacy_accepted: false,
        signed_name: null,
        signed_department: null,
        privacy_accepted_at: null
    }).eq('id', userId);
    return !error;
  },

  // Realtime
  subscribeToPresence(user: User, callback: (users: OnlineUser[]) => void) {
    if (!supabase) return null;
    const channel = supabase.channel('online-users');
    channel
        .on('presence', { event: 'sync' }, () => {
            const newState = channel.presenceState();
            const users: OnlineUser[] = [];
            for (const key in newState) {
                // @ts-ignore
                users.push(...newState[key]);
            }
            callback(users);
        })
        .subscribe(async (status) => {
            if (status === 'SUBSCRIBED') {
                await channel.track({
                    userId: user.$id,
                    name: user.name,
                    email: user.email,
                    area: user.area,
                    role: user.role,
                    onlineAt: new Date().toISOString()
                });
            }
        });
    return channel;
  },

  unsubscribeFromPresence(channel: any) {
    if (channel) channel.unsubscribe();
  },

  // Admin User Management
  async adminGetAllUsers(): Promise<User[]> {
    if (!supabase) return [];
    const { data } = await supabase.from('users').select('*');
    if (!data) return [];
    return data.map((u: any) => ({
         $id: u.id,
         name: u.name,
         email: u.email,
         area: u.area,
         allowedAreas: u.allowed_areas || [],
         role: u.role,
         avatarUrl: u.avatar_url,
         privacyAccepted: u.privacy_accepted,
         signedName: u.signed_name,
         signedDepartment: u.signed_department,
