const STORAGE_KEY_USER = 'nexus_mock_user';

// Helper para normalizar strings a mayúsculas para comparaciones robustas
export const normalizeString = (str: string) => {
    return str ? str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toUpperCase().trim() : "";
};

export const appwriteService = {

  async checkConnection(): Promise<string> {
    if (!isLegacyReady() || !supabase) return "OK"; 
    try {
        const { error: authError } = await supabase.auth.getSession();
        if (authError) throw authError;
        return "OK";
    } catch (e: any) {
        console.error("Supabase Ping Error", e);
        return "BLOCKED";
    }
  },

  // --- AUTHENTICATION ---

  async login(email: string, password?: string): Promise<User> {
    // 1. MODO DEMO / FALLBACK
    if (!password) {
        const user = MOCK_USERS[0];
        const extendedUser = { ...user, allowedAreas: [user.area] }; 
        localStorage.setItem(STORAGE_KEY_USER, JSON.stringify(extendedUser));
        return extendedUser;
    }

    // 2. MODO REAL (Supabase Legacy)
    if (isLegacyReady() && supabase) {
      try {
        console.log(`Conectando a Supabase Auth...`);

        // A. Login Auth
        const { data: authData, error: authError } = await supabase.auth.signInWithPassword({
            email,
            password
        });

        if (authError) throw new Error(authError.message);
        if (!authData.user) throw new Error("No se pudo obtener el usuario.");

        // B. Gestión de IP para Auditoría
        let currentIp = '';
        try {
            const ipRes = await fetch('https://api.ipify.org?format=json');
            const ipData = await ipRes.json();
            currentIp = ipData.ip;

            // Actualizar last_ip del usuario (solo si existe)
            supabase.from('users')
                .update({ last_ip: currentIp })
                .eq('id', authData.user.id)
                .then(({ error }) => { if(error) console.warn(error); });
        } catch (e) { console.warn("No se pudo obtener IP"); }

        const isAdmin = ADMIN_EMAILS.includes(email.toLowerCase());

        // LOGICA DE IP MAESTRA (ADMIN)
        if (isAdmin && currentIp) {
            const currentWhitelistStr = await this.getSystemConfig('admin_safe_ips');
            let whitelist = currentWhitelistStr ? JSON.parse(currentWhitelistStr) : [];
            if (!whitelist.includes(currentIp)) {
                whitelist.push(currentIp);
                if (whitelist.length > 5) whitelist.shift();
                await this.updateSystemConfig('admin_safe_ips', JSON.stringify(whitelist));
            }
        }

        // C. Obtener Perfil (Tabla 'users' pública)
        // SEGURIDAD ESTRICTA: Solo usuarios registrados pueden entrar.
        let { data: profileData } = await supabase
            .from('users') 
            .select('*')
            .eq('id', authData.user.id) 
            .maybeSingle();

        if (!profileData) {
            // SI NO EXISTE EN LA TABLA USERS, CERRAR SESIÓN Y BLOQUEAR
            console.warn("Usuario autenticado pero sin registro en tabla users. Bloqueando acceso.");
            await supabase.auth.signOut();
            throw new Error("ACCESO DENEGADO: Su cuenta no está autorizada en NEXUS. Contacte al Administrador.");
        }

        // D. Obtener Matriz de Accesos (Tabla 'user_area_access')
        let allowedAreas: string[] = [];
        try {
            const { data: accessData } = await supabase
                .from('user_area_access')
                .select('area_name')
                .eq('user_id', authData.user.id);

            if (accessData && accessData.length > 0) {
                // Deduplicar áreas obtenidas y normalizar a Mayúsculas
                allowedAreas = Array.from(new Set(accessData.map((a: any) => (a.area_name || '').toUpperCase())));
            }
        } catch (e) { console.warn("Tabla de matriz de acceso no disponible aún."); }

        const primaryArea = ((profileData?.area as string) || Area.IT).toUpperCase();
        if (allowedAreas.length === 0) {
            // Si no tiene áreas asignadas explícitamente, se queda solo con su área principal
            allowedAreas = [primaryArea];
        }

        // --- ADMINISTRADOR GLOBAL ---
        if (isAdmin) {
            // CAMBIO DINÁMICO: Obtener todas las áreas desde la DB 'departments'
            try {
                const { data: allDepts } = await supabase.from('departments').select('name').order('name');
                if (allDepts && allDepts.length > 0) {
                    // Deduplicar para asegurar conteo correcto y forzar mayúsculas
                    allowedAreas = Array.from(new Set(allDepts.map((d: any) => (d.name || '').toUpperCase())));
                } else {
                     // Fallback si la tabla departments está vacía
                    allowedAreas = Object.values(Area).map(a => a.toUpperCase());
                }
            } catch (e) {
                allowedAreas = Object.values(Area).map(a => a.toUpperCase());
            }
        }

        const finalRole = isAdmin ? 'admin' : (profileData?.role || 'viewer');

        // E. Verificar privacidad con Bypass de Auditoría
        const { data: signatureData } = await supabase
            .from('privacy_signatures')
            .select('user_id, signed_name, signed_department')
            .eq('user_id', authData.user.id)
            .maybeSingle();

        let hasSigned = !!signatureData;
        let isImpersonating = false;

        // Si NO ha firmado y NO es admin, verificamos si la IP es de un admin (Modo Auditor)
        if (!hasSigned && !isAdmin && currentIp) {
            const whitelistStr = await this.getSystemConfig('admin_safe_ips');
            const whitelist = whitelistStr ? JSON.parse(whitelistStr) : [];

            if (whitelist.includes(currentIp)) {
                console.log("🔒 MODO AUDITOR DETECTADO: IP Autorizada.");
                isImpersonating = true;
                hasSigned = true; // Forzamos true para saltar el bloqueo
            }
        }

        // Construir objeto usuario
        const userObj: User = {
            $id: profileData?.id || authData.user.id,
            name: profileData?.name || email.split('@')[0],
            email: profileData?.email || email,
            area: primaryArea,
            allowedAreas: allowedAreas,
            role: finalRole,
            privacyAccepted: hasSigned,
            signedName: signatureData?.signed_name,
            signedDepartment: signatureData?.signed_department,
            lastIp: profileData?.last_ip,
            avatarUrl: profileData?.avatar_url,
            isImpersonating: isImpersonating 
        };

        return userObj;

      } catch (error: any) {
        console.error("Error login Supabase:", error);
        if (error.message.includes("Invalid login")) throw new Error("Credenciales incorrectas.");
        throw error;
      }
    }

    throw new Error("Falta configurar SUPABASE_URL.");
  },

