                                        onClick={() => handleDownloadResponse(req.id, 'rejected')}
                                        className="flex-1 py-3 border border-red-200 text-red-600 font-bold text-sm rounded-lg hover:bg-red-50 transition-colors"
                                    >
                                        Denegar
                                    </button>
                                    <button 
                                        onClick={() => handleDownloadResponse(req.id, 'approved')}
                                        className="flex-1 py-3 bg-emerald-600 text-white font-bold text-sm rounded-lg hover:bg-emerald-700 shadow-sm transition-colors flex items-center justify-center"
                                    >
                                        <CheckCircle size={16} className="mr-2" />
                                        Autorizar
                                    </button>
                                </div>
                            ) : (
