import { User, Procedure, Folder, Stats, ConsultationMessage, DownloadRequest, OnlineUser, ADMIN_EMAILS } from '../types';
import { MOCK_USERS, MOCK_PROCEDURES } from './mockData';

export const normalizeString = (str: string) => {
  if (!str) return '';
  return str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase().trim();
};

// In-memory store for the session (mock database)
let users = JSON.parse(JSON.stringify(MOCK_USERS)) as User[];
let procedures = JSON.parse(JSON.stringify(MOCK_PROCEDURES)) as Procedure[];
let messages: ConsultationMessage[] = [];
let downloadRequests: DownloadRequest[] = [];
let systemConfigs: Record<string, string> = {};

// Mock delay to simulate network
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const appwriteService = {

  async getCurrentUser(): Promise<User | null> {
    const stored = localStorage.getItem('nexus_user');
    if (stored) return JSON.parse(stored);
    return null;
  },

  async login(email: string, password?: string): Promise<User> {
    await delay(500);
    // Find user in mock users or admins
    let user = users.find(u => u.email === email);

    // Auto-create admin if in list and not found (simulating dynamic provision)
    if (!user && ADMIN_EMAILS.includes(email)) {
       user = {
         $id: `user_${Date.now()}`,
         name: 'Admin User',
         email,
         area: 'Administración',
         allowedAreas: ['Administración', 'IT', 'HR'], // Super user
         role: 'admin',
         privacyAccepted: true
       };
       users.push(user);
    }

    if (user) {
        localStorage.setItem('nexus_user', JSON.stringify(user));
        return user;
    }
    throw new Error('Usuario no encontrado en mocks (Intente: juan@uad.com).');
  },

  async logout(): Promise<void> {
    localStorage.removeItem('nexus_user');
  },

  async updateUserPrivacy(userId: string, signedName?: string, signedDepartment?: string): Promise<boolean> {
      const u = users.find(u => u.$id === userId);
      if (u) {
          u.privacyAccepted = true;
          u.signedName = signedName;
          u.signedDepartment = signedDepartment;

          // Update local storage if it's current user
          const current = await this.getCurrentUser();
          if (current && current.$id === userId) {
             const updated = { ...current, privacyAccepted: true, signedName, signedDepartment };
             localStorage.setItem('nexus_user', JSON.stringify(updated));
          }
          return true;
      }
      return false;
  },

  async uploadUserAvatar(userId: string, file: File): Promise<string | null> {
      return URL.createObjectURL(file); // Mock URL
  },

  // Presence Mock
  subscribeToPresence(user: User, callback: (users: OnlineUser[]) => void): any {
      const online: OnlineUser[] = [
          { userId: user.$id, name: user.name, email: user.email, area: user.area, role: user.role, onlineAt: new Date().toISOString() }
      ];
      // Simulate updates
      callback(online);
      return online;
  },

  unsubscribeFromPresence(subscription: any): void {
      // no-op
  },

  // Stats & Procedures
  async getStats(allowedAreas: string[]): Promise<Stats> {
      const active = procedures.filter(p => p.status === 'Vigente').length;
      const review = procedures.filter(p => p.status === 'En Revisión').length;
      return { totalActive: active, totalReview: review, lastUpdated: new Date().toISOString() };
  },

  async getProcedures(user: User, searchTerm?: string, area?: string): Promise<Procedure[]> {
      await delay(300);
      let result = procedures;

      if (searchTerm) {
          const lower = normalizeString(searchTerm);
          result = result.filter(p => 
              normalizeString(p.name).includes(lower) || 
              normalizeString(p.code).includes(lower) ||
              normalizeString(p.description).includes(lower)
          );
      }

      if (area) {
          result = result.filter(p => normalizeString(p.area) === normalizeString(area));
      }

      return result;
  },

  async getFolders(area: string): Promise<Folder[]> {
      // Mock some folders
      return [
          { id: 'f1', name: 'Manuales Operativos', parent_id: null, created_at: '', area },
          { id: 'f2', name: 'Formatos', parent_id: null, created_at: '', area }
      ];
  },

  async getAllAreas(): Promise<string[]> {
      const areas = new Set(procedures.map(p => p.area));
      return Array.from(areas);
  },

  async getProcedureById(id: string): Promise<Procedure | undefined> {
      return procedures.find(p => p.$id === id);
  },

  // Admin Area Management
  async createArea(name: string): Promise<boolean> { return true; },
  async renameArea(oldName: string, newName: string): Promise<boolean> { return true; },
  async deleteArea(name: string): Promise<boolean> { return true; },

  // Downloads
  async getDownloadStatus(userId: string, procedureId: string): Promise<DownloadRequest | null> {
      return downloadRequests.find(r => r.user_id === userId && r.procedure_id === procedureId) || null;
  },

  async requestDownload(userId: string, procedureId: string, procedureName: string): Promise<boolean> {
      const u = users.find(user => user.$id === userId);
      const req: DownloadRequest = {
          id: `req_${Date.now()}`,
          user_id: userId,
          procedure_id: procedureId,
          procedure_name: procedureName,
          status: 'pending',
          requested_at: new Date().toISOString(),
          user_name: u?.name,
          user_email: u?.email,
          user_area: u?.area
      };
      downloadRequests.push(req);
      return true;
  },

  async consumeDownloadToken(requestId: string): Promise<boolean> {
      const req = downloadRequests.find(r => r.id === requestId);
      if (req) {
          req.status = 'consumed';
          return true;
      }
      return false;
  },

  // Consultation
  async getCollaborativeMessages(allowedAreas: string[]): Promise<ConsultationMessage[]> {
      return messages;
  },

  async sendConsultationMessage(userId: string, message: string, area: string, procId?: string, procName?: string, title?: string): Promise<boolean> {
      const u = users.find(u => u.$id === userId);
      const msg: ConsultationMessage = {
          id: `msg_${Date.now()}`,
          user_id: userId,
          message,
          area,
          procedure_id: procId,
          procedure_name: procName,
          title,
          status: 'pending',
          created_at: new Date().toISOString(),
          user_name: u?.name,
          user_email: u?.email,
          user_area: u?.area,
          user_role: u?.role,
          replies: []
      };
      messages.push(msg);
      return true;
  },

  async replyToMessage(ticketId: string, userId: string, text: string): Promise<boolean> {
      const msg = messages.find(m => m.id === ticketId);
      const u = users.find(user => user.$id === userId);
      if (msg && u) {
          if (!msg.replies) msg.replies = [];
          msg.replies.push({
              id: `rep_${Date.now()}`,
              message_id: ticketId,
              user_id: userId,
              message: text,
              created_at: new Date().toISOString(),
              user_name: u.name,
              user_role: u.role
          });
          return true;
      }
      return false;
  },

  // Admin
  async adminGetAllUsers(): Promise<User[]> {
      return users;
  },

  async adminGetConsultationMessages(): Promise<ConsultationMessage[]> {
      return messages;
  },

  async adminGetDownloadRequests(): Promise<DownloadRequest[]> {
      return downloadRequests;
  },

  async adminRespondToDownloadRequest(requestId: string, status: 'approved' | 'rejected'): Promise<boolean> {
      const req = downloadRequests.find(r => r.id === requestId);
      if (req) {
          req.status = status;
          return true;
      }
      return false;
  },

  async adminDeleteDownloadRequest(requestId: string): Promise<boolean> {
      downloadRequests = downloadRequests.filter(r => r.id !== requestId);
      return true;
  },

  async adminUpdateMessageStatus(id: string, status: any): Promise<boolean> {
      const msg = messages.find(m => m.id === id);
      if (msg) {
          msg.status = status;
          return true;
      }
      return false;
  },

  async adminDeleteMessage(id: string): Promise<boolean> {
      messages = messages.filter(m => m.id !== id);
      return true;
  },

  // System Config
  async getSystemConfig(key: string): Promise<string> {
      return systemConfigs[key] || '';
  },

  async updateSystemConfig(key: string, value: string): Promise<boolean> {
      systemConfigs[key] = value;
      return true;
  },

  async deleteUserPrivacySignature(userId: string): Promise<boolean> {
      const u = users.find(u => u.$id === userId);
      if (u) {
          u.privacyAccepted = false;
          // Also update session if active
          const current = await this.getCurrentUser();
          if (current && current.$id === userId) {
             const updated = { ...current, privacyAccepted: false };
             localStorage.setItem('nexus_user', JSON.stringify(updated));
          }
          return true;
      }
      return false;
  }
};

