import { createClient, RealtimeChannel } from '@supabase/supabase-js';
import { Area, ConsultationMessage, DownloadRequest, Folder, OnlineUser, Procedure, Stats, Status, User } from '../types';

// Initialize Supabase with environment variables
const supabaseUrl = import.meta.env.VITE_SUPABASE_URL || '';
const supabaseKey = import.meta.env.VITE_SUPABASE_ANON_KEY || '';

export const supabase = createClient(supabaseUrl, supabaseKey);

const isLegacyReady = () => !!supabase;

export const normalizeString = (str: string) => {
  return str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase().trim();
};

export const appwriteService = {

  // --- AUTH ---
  async getCurrentUser(): Promise<User | null> {
    const { data: { session } } = await supabase.auth.getSession();
    if (!session?.user) return null;

    const { data: profile } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', session.user.id)
        .single();

    if (!profile) {
        // Fallback for user without profile row
        return {
            $id: session.user.id,
            name: session.user.email?.split('@')[0] || 'User',
            email: session.user.email || '',
            area: 'Invitado',
            allowedAreas: ['Invitado'],
            role: 'collaborator',
            privacyAccepted: false
        };
    }

    return {
        $id: profile.id,
        name: profile.full_name || session.user.email?.split('@')[0] || 'User',
        email: session.user.email || '',
        area: profile.area || 'Invitado',
        allowedAreas: profile.allowed_areas || [profile.area || 'Invitado'],
        role: profile.role || 'collaborator',
        avatarUrl: profile.avatar_url,
        privacyAccepted: profile.privacy_accepted,
        signedName: profile.signed_name,
        signedDepartment: profile.signed_department,
        lastIp: '127.0.0.1', 
        isImpersonating: false
    };
  },

  async login(email: string, password?: string): Promise<User | null> {
     const { error } = await supabase.auth.signInWithPassword({ email, password: password || '' });
     if (error) throw error;
     return this.getCurrentUser();
  },

  async logout(): Promise<void> {
    await supabase.auth.signOut();
  },

  async updateUserPrivacy(userId: string, signedName?: string, signedDepartment?: string): Promise<boolean> {
     const { error } = await supabase.from('profiles').update({
         privacy_accepted: true,
         signed_name: signedName,
         signed_department: signedDepartment,
         privacy_accepted_at: new Date().toISOString()
     }).eq('id', userId);
     return !error;
  },

  async deleteUserPrivacySignature(userId: string): Promise<boolean> {
      const { error } = await supabase.from('profiles').update({
          privacy_accepted: false,
          signed_name: null,
          signed_department: null,
          privacy_accepted_at: null
      }).eq('id', userId);
      return !error;
  },

  async uploadUserAvatar(userId: string, file: File): Promise<string | null> {
      const fileExt = file.name.split('.').pop();
      const fileName = `${userId}-${Math.random()}.${fileExt}`;
      const filePath = `avatars/${fileName}`;

      const { error: uploadError } = await supabase.storage.from('avatars').upload(filePath, file);
      if (uploadError) return null;

      const { data } = supabase.storage.from('avatars').getPublicUrl(filePath);

      // Update profile
      await supabase.from('profiles').update({ avatar_url: data.publicUrl }).eq('id', userId);

      return data.publicUrl;
  },

  // --- REALTIME PRESENCE ---
  subscribeToPresence(user: User, callback: (users: OnlineUser[]) => void): RealtimeChannel {
      const channel = supabase.channel('online-users');

      channel
        .on('presence', { event: 'sync' }, () => {
            const state = channel.presenceState();
            const users: OnlineUser[] = [];
            for (const id in state) {
                // @ts-ignore
                const presence = state[id][0];
                users.push(presence as OnlineUser);
            }
            callback(users);
        })
        .subscribe(async (status) => {
            if (status === 'SUBSCRIBED') {
                await channel.track({
                    userId: user.$id,
                    name: user.name,
                    email: user.email,
                    area: user.area,
                    role: user.role,
                    onlineAt: new Date().toISOString()
                });
            }
        });

      return channel;
  },

  unsubscribeFromPresence(channel: RealtimeChannel) {
      supabase.removeChannel(channel);
  },

  // --- DATA / PROCEDURES ---
  async getStats(allowedAreas: string[]): Promise<Stats> {
      // Return basic stats
      return {
          totalActive: 10,
          totalReview: 2,
          lastUpdated: new Date().toISOString()
      };
  },

  async getProcedures(user: User, searchTerm?: string, area?: string): Promise<Procedure[]> {
    let query = supabase.from('procedures').select('*');

    if (area) {
        query = query.eq('area', area);
    }

    if (searchTerm) {
        query = query.ilike('name', `%${searchTerm}%`);
    }

    const { data, error } = await query;
    if (error || !data) return [];

    return data.map((p: any) => ({
        $id: p.id,
        name: p.name,
        code: p.code,
        area: p.area,
        version: p.version,
        status: p.status,
        description: p.description,
        attachmentUrl: p.attachment_url,
        urlVideo: p.url_video,
        folder_id: p.folder_id,
        updatedAt: p.updated_at,
        responsible: p.responsible,
        history: p.history || []
    }));
  },

  async getProcedureById(id: string): Promise<Procedure | null> {
      const { data, error } = await supabase.from('procedures').select('*').eq('id', id).single();
      if (error || !data) return null;
      return {
          $id: data.id,
          name: data.name,
          code: data.code,
          area: data.area,
          version: data.version,
          status: data.status,
          description: data.description,
          attachmentUrl: data.attachment_url,
          urlVideo: data.url_video,
          folder_id: data.folder_id,
          updatedAt: data.updated_at,
          responsible: data.responsible,
          history: data.history || []
      };
  },

  async getFolders(area: string): Promise<Folder[]> {
      const { data } = await supabase.from('folders').select('*').eq('area', area);
      if (!data) return [];
      return data.map((f: any) => ({
          id: f.id,
          name: f.name,
          parent_id: f.parent_id,
          created_at: f.created_at,
          area: f.area
      }));
  },

  async getAllAreas(): Promise<string[]> {
      const { data } = await supabase.from('areas').select('name');
      return data?.map((a: any) => a.name) || [];
  },

  async createArea(name: string): Promise<boolean> {
      const { error } = await supabase.from('areas').insert({ name });
      return !error;
  },

  async renameArea(oldName: string, newName: string): Promise<boolean> {
      const { error } = await supabase.from('areas').update({ name: newName }).eq('name', oldName);
      return !error;
  },

  async deleteArea(name: string): Promise<boolean> {
      const { error } = await supabase.from('areas').delete().eq('name', name);
      return !error;
  },

  // --- DOWNLOAD REQUESTS ---
  async getDownloadStatus(userId: string, procedureId: string): Promise<DownloadRequest | null> {
      const { data } = await supabase.from('download_requests')
        .select('*')
        .eq('user_id', userId)
        .eq('procedure_id', procedureId)
        .maybeSingle();

      if (!data) return null;
      return data as DownloadRequest;
  },

  async requestDownload(userId: string, procedureId: string, procedureName: string): Promise<boolean> {
      const { error } = await supabase.from('download_requests').insert({
          user_id: userId,
          procedure_id: procedureId,
          procedure_name: procedureName,
          status: 'pending',
          requested_at: new Date().toISOString()
