import { createClient } from '@supabase/supabase-js';
import { Area, Procedure, Status, User, OnlineUser, ConsultationMessage, DownloadRequest, Folder, Stats } from '../types';
import { MOCK_USERS, MOCK_PROCEDURES } from './mockData';

// Placeholder configuration - In a real app these come from env vars
const SUPABASE_URL = process.env.REACT_APP_SUPABASE_URL || '';
const SUPABASE_KEY = process.env.REACT_APP_SUPABASE_KEY || '';

// Initialize Supabase if keys are present
const supabase = (SUPABASE_URL && SUPABASE_KEY) 
  ? createClient(SUPABASE_URL, SUPABASE_KEY) 
  : null;

const isLegacyReady = () => !!supabase;

export const normalizeString = (str: string) => {
  return str ? str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase() : "";
};

export const appwriteService = {
  // --- AUTHENTICATION ---
  async getCurrentUser(): Promise<User | null> {
    if (!isLegacyReady()) return MOCK_USERS[0]; // Fallback to Mock

    try {
      const { data: { user } } = await supabase!.auth.getUser();
      if (!user) return null;

      // Fetch profile from 'profiles' table
      const { data: profile } = await supabase!
        .from('profiles')
        .select('*')
        .eq('id', user.id)
        .single();

      if (profile) return { ...profile, $id: profile.id } as User;

      // Basic fallback if profile missing
      return { 
        $id: user.id, 
        name: user.user_metadata.name || 'Usuario', 
        email: user.email || '', 
        area: 'Invitado', 
        allowedAreas: ['Invitado'], 
        role: 'user' 
      };
    } catch (e) {
      console.error("Auth Error", e);
      return null;
    }
  },

  async login(email: string, password?: string): Promise<User | null> {
    if (!isLegacyReady()) {
      console.warn("Supabase not configured. Using Mock login.");
      const mockUser = MOCK_USERS.find(u => u.email === email);
      if (mockUser) return mockUser;
      throw new Error("Usuario no encontrado (Mock)");
    }

    const { error } = await supabase!.auth.signInWithPassword({
      email,
      password: password || '12345678', // Default password logic if needed
    });

    if (error) throw error;
