  // --- PRESENCE (REALTIME) ---
  subscribeToPresence(user: User, callback: (users: OnlineUser[]) => void): any {
    if (!isLegacyReady()) return null;

    const channel = supabase!.channel('online-users');
    channel
      .on('presence', { event: 'sync' }, () => {
        const state = channel.presenceState();
        const users: OnlineUser[] = [];
        Object.values(state).forEach((presences: any) => {
             users.push(...presences);
        });
        // Remove duplicates if any
        const uniqueUsers = Array.from(new Map(users.map(u => [u.userId, u])).values());
        callback(uniqueUsers);
      })
      .subscribe(async (status) => {
        if (status === 'SUBSCRIBED') {
          await channel.track({
            userId: user.$id,
            name: user.name,
            email: user.email,
            area: user.area,
            role: user.role,
            onlineAt: new Date().toISOString()
          });
        }
      });
    return channel;
  },

  unsubscribeFromPresence(channel: any) {
    if (channel && supabase) {
      supabase.removeChannel(channel);
    }
  },

