  async getProcedures(user: User, search: string = '', area?: string): Promise<Procedure[]> {
    if (isLegacyReady()) {
      let query = supabase!.from('procedures').select('*');

      if (search) {
          query = query.ilike('name', `%${search}%`);
      } else if (area) {
          query = query.eq('area', area);
      }

      const { data } = await query;
      return data ? data.map(p => ({...p, $id: p.id || p.$id})) as Procedure[] : [];
    }

    // Filter Mock Data
    let docs = MOCK_PROCEDURES;
    if (area) docs = docs.filter(p => p.area === area);
    if (search) docs = docs.filter(p => p.name.toLowerCase().includes(search.toLowerCase()));
    return docs;
  },

